const WelcomeLoader: React.FC<{ onComplete: () => void }> = ({ onComplete }) => {
  const [progress, setProgress] = useState(0);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    const timer = setInterval(() => {
      setProgress((prev) => {
        if (prev >= 100) {
          clearInterval(timer);
          setTimeout(onComplete, 500);
          return 100;
        }
        return prev + 5;
      });
    }, 100);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      clearInterval(timer);
    };
  }, [onComplete]);

  return (
    <div className="fixed inset-0 bg-gray-900 z-[300] flex flex-col items-center justify-center p-6 text-center overflow-hidden">
      <div className="absolute top-[-20%] left-[-10%] w-96 h-96 bg-[#FA8072]/10 rounded-full blur-[100px] animate-pulse"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-96 h-96 bg-blue-500/10 rounded-full blur-[120px] animate-pulse"></div>
      <div className="relative z-10 max-w-sm w-full">
        <div className="mb-8 relative">
           <div className="w-24 h-24 bg-gradient-to-tr from-[#FA8072] to-orange-600 rounded-[2rem] flex items-center justify-center mx-auto shadow-2xl shadow-orange-500/20 animate-bounce">
              <ShieldCheck className="text-white" size={48} />
           </div>
           {progress === 100 && (
             <div className="absolute -right-2 -bottom-2 bg-green-500 text-white p-1 rounded-full animate-fade-up">
                <CheckCircle2 size={24} />
             </div>
           )}
        </div>
        <h2 className="text-2xl font-black text-white mb-2 animate-fade-up">أهلاً بك في مخبز كوكيز</h2>
        <p className="text-gray-400 text-sm font-bold mb-8 h-10">
          {progress < 40 && "جاري الاتصال بقاعدة البيانات المحلية..."}
          {progress >= 40 && progress < 80 && "تأمين الملفات للعمل بوضعية الأوفلاين..."}
          {progress >= 80 && progress < 100 && "مزامنة البيانات السحابية..."}
          {progress === 100 && "النظام جاهز للعمل الآن"}
        </p>
        <div className="w-full bg-gray-800 h-3 rounded-full overflow-hidden border border-gray-700 mb-4 p-0.5">
          <div className="h-full bg-gradient-to-r from-[#FA8072] to-orange-500 rounded-full transition-all duration-300 ease-out shadow-lg shadow-orange-500/30" style={{ width: `${progress}%` }}></div>
        </div>
        <div className="flex justify-between items-center px-1">
          <div className="flex items-center gap-2">
             {isOnline ? (
               <Wifi size={14} className={progress < 100 ? "animate-pulse text-blue-400" : "text-green-500"} />
             ) : (
               <WifiOff size={14} className="text-red-500 animate-pulse" />
             )}
             <span className={`text-[10px] font-black uppercase tracking-widest ${isOnline ? 'text-gray-500' : 'text-red-500'}`}>
               {isOnline ? 'OFFLINE READY' : 'WORKING OFFLINE'}
             </span>
          </div>
          <span className="text-[#FA8072] font-black tabular-nums">{progress}%</span>
        </div>
      </div>
      <div className="absolute bottom-10 flex items-center gap-2 text-gray-600">
          <CloudDownload size={14} />
          <span className="text-[8px] font-black uppercase tracking-[0.3em]">Downloading System Assets</span>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => sessionStorage.getItem('isAuth') === 'true');
  const [isInitializing, setIsInitializing] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSyncTime, setLastSyncTime] = useState<Date>(() => new Date());
  const [showLock, setShowLock] = useState<{ target: string; data?: any } | null>(null);
  const [lockPass, setLockPass] = useState('');
  const [lockError, setLockError] = useState(false);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  // PWA Install Prompt State
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  useEffect(() => {
    const handleBeforeInstallPrompt = (e: any) => {
      e.preventDefault();
      setInstallPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    return () => window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
  }, []);

  const handleInstall = async () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    const { outcome } = await installPrompt.userChoice;
    if (outcome === 'accepted') {
      setInstallPrompt(null);
    }
  };

  const [systemPassword, setSystemPassword] = useState(() => localStorage.getItem('systemPassword') || '2026');

  const [showBackupReminder, setShowBackupReminder] = useState(false);
  const lastBackupTimestamp = useRef<number>(Date.now());

  const [sales, setSales] = useState<SaleItem[]>(() => JSON.parse(localStorage.getItem('dailySales') || '[]'));
  const [purchaseInvoices, setPurchaseInvoices] = useState<PurchaseInvoice[]>(() => JSON.parse(localStorage.getItem('dailyPurchaseInvoices') || '[]'));
  const [history, setHistory] = useState<ArchivedDay[]>(() => JSON.parse(localStorage.getItem('salesHistory') || '[]'));
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem('products') || '[]'));
  const [customers, setCustomers] = useState<Customer[]>(() => JSON.parse(localStorage.getItem('customers') || '[]'));
  const [suppliers, setSuppliers] = useState<Supplier[]>(() => JSON.parse(localStorage.getItem('suppliers') || '[]'));

  const [invoiceItems, setInvoiceItems] = useState<SaleItem[] | null>(null);
  const [modals, setModals] = useState({ products: false, customers: false, history: false, data: false, expenses: false, analytics: false });

  const handleLogout = () => {
    sessionStorage.removeItem('isAuth');
    setIsAuthenticated(false);
  };

  const handleOpenProtected = (target: string, data?: any) => {
    setShowLock({ target, data });
  };

  const completeOrder = useCallback((items: any[], customerName?: string, customerId?: string, saleType: SaleType = 'retail') => {
    const orderId = Date.now().toString();
    const time = new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: false });
    const todayDate = new Date().toLocaleDateString('en-US');

    const activeTodaySales = sales.filter(s => s.date === todayDate);
    const activeMax = activeTodaySales.length > 0 
      ? Math.max(...activeTodaySales.map(s => s.customerNumber)) 
      : 0;

    const archivedToday = history.find(h => h.date === todayDate);
    const archivedMax = (archivedToday && archivedToday.items.length > 0)
      ? Math.max(...archivedToday.items.map(s => s.customerNumber))
      : 0;

    const nextCustomerNumber = Math.max(activeMax, archivedMax) + 1;

    const newItems: SaleItem[] = items.map(item => ({
      ...item,
      id: Math.random().toString(36).substr(2, 9),
      orderId,
      customerNumber: nextCustomerNumber,
      customerName,
      customerId,
      saleType,
      time,
      date: todayDate
    }));

    setSales(prev => [...prev, ...newItems]);
    setInvoiceItems(newItems);
  }, [sales, history]);

  const handleUpdateProduct = (id: string, updatedProduct: Partial<Product>) => {
    setProducts(prev => prev.map(p => p.id === id ? { ...p, ...updatedProduct } : p));
  };

  const handleUpdateArchivedOrder = (dayId: string, orderId: string, updatedItems: SaleItem[], newCustomerName?: string) => {
    setHistory(prev => prev.map(day => {
      if (day.id === dayId) {
        const otherItems = day.items.filter(item => item.orderId !== orderId);
        const finalItems = [...otherItems, ...updatedItems.map(it => ({ ...it, customerName: newCustomerName || it.customerName }))];
        return {
          ...day,
          items: finalItems,
          totalRevenue: finalItems.reduce((s, i) => s + (i.price * i.quantity), 0),
          totalItems: finalItems.length
        };
      }
      return day;
    }));
  };

  const handleDeleteArchivedOrder = (dayId: string, orderId: string) => {
    setHistory(prev => {
      const updated = prev.map(day => {
        if (day.id === dayId) {
          const finalItems = day.items.filter(item => item.orderId !== orderId);
          return {
            ...day,
            items: finalItems,
            totalRevenue: finalItems.reduce((s, i) => s + (i.price * i.quantity), 0),
            totalItems: finalItems.length
          };
        }
        return day;
      });
      return updated.filter(day => day.items.length > 0 || (day.purchaseInvoices && day.purchaseInvoices.length > 0));
    });
  };

  const handleDeleteArchivedDay = (dayId: string) => {
    setHistory(prev => prev.filter(day => day.id !== dayId));
  };

  const handleLoginSuccess = () => {
    sessionStorage.setItem('isAuth', 'true');
    setIsInitializing(true);
  };

  const finalizeLogin = () => {
    setIsInitializing(false);
    setIsAuthenticated(true);
  };

  useEffect(() => {
    if (!isAuthenticated) return;
    const CHECK_INTERVAL = 60 * 1000; 
    const REMINDER_INTERVAL = 60 * 60 * 1000; 
    const intervalId = setInterval(() => {
      const now = Date.now();
      if (now - lastBackupTimestamp.current >= REMINDER_INTERVAL) {
        setShowBackupReminder(true);
      }
    }, CHECK_INTERVAL);
    return () => clearInterval(intervalId);
  }, [isAuthenticated]);

  useEffect(() => {
    localStorage.setItem('dailySales', JSON.stringify(sales));
    localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(purchaseInvoices));
    localStorage.setItem('salesHistory', JSON.stringify(history));
    localStorage.setItem('products', JSON.stringify(products));
    localStorage.setItem('customers', JSON.stringify(customers));
    localStorage.setItem('suppliers', JSON.stringify(suppliers));
    localStorage.setItem('systemPassword', systemPassword);
    setLastSyncTime(new Date());
  }, [sales, purchaseInvoices, history, products, customers, suppliers, systemPassword]);

  const verifyLock = () => {
    if (lockPass === systemPassword) {
      if (showLock?.target === 'full_reset') {
          localStorage.clear();
          window.location.reload();
      } else if (showLock?.target === 'clear_all_history') {
          setHistory([]);
      } else if (showLock) {
          setModals(m => ({ ...m, [showLock.target]: true }));
      }
      setShowLock(null);
      setLockPass('');
      setLockError(false);
    } else {
      setLockError(true);
    }
  };

  const handleArchiveDay = useCallback(() => {
      if (sales.length === 0 && purchaseInvoices.length === 0) {
          alert('لا توجد عمليات مبيعات أو مشتريات نشطة حالياً لترحيلها.');
          return;
      }

      const confirmed = window.confirm('هل أنت متأكد من ترحيل المبيعات للأرشيف وتصفير اليوم؟ \n\nسيتم توزيع كل فاتورة حسب تاريخها الأصلي في السجلات التاريخية.');
      if (!confirmed) return;

      try {
          const currentSales = [...sales];
          const currentPurchases = [...purchaseInvoices];

          const salesMap = new Map<string, SaleItem[]>();
          currentSales.forEach(s => {
              const d = s.date;
              if (!salesMap.has(d)) salesMap.set(d, []);
              salesMap.get(d)!.push(s);
          });

          const purchaseMap = new Map<string, PurchaseInvoice[]>();
          currentPurchases.forEach(p => {
              const d = p.date;
              if (!purchaseMap.has(d)) purchaseMap.set(d, []);
              purchaseMap.get(d)!.push(p);
          });

          const allUniqueDates = Array.from(new Set([...salesMap.keys(), ...purchaseMap.keys()]));

          setHistory(prev => {
              const newHistory = [...prev];

              allUniqueDates.forEach(dateStr => {
                  const daySales = salesMap.get(dateStr) || [];
                  const dayPurchases = purchaseMap.get(dateStr) || [];

                  const rev = daySales.reduce((s, i) => s + (i.price * i.quantity), 0);
                  const exp = dayPurchases.reduce((s, i) => s + i.totalAmount, 0);

                  const existingIdx = newHistory.findIndex(h => h.date === dateStr);

                  if (existingIdx !== -1) {
                      newHistory[existingIdx] = {
                          ...newHistory[existingIdx],
                          items: [...newHistory[existingIdx].items, ...daySales],
                          purchaseInvoices: [...(newHistory[existingIdx].purchaseInvoices || []), ...dayPurchases],
                          totalRevenue: newHistory[existingIdx].totalRevenue + rev,
                          totalExpenses: newHistory[existingIdx].totalExpenses + exp,
                          totalItems: newHistory[existingIdx].totalItems + daySales.length
                      };
                  } else {
                      const refItem = daySales[0];
                      const ts = refItem ? parseInt(refItem.orderId) : Date.now();

                      newHistory.push({
                          id: `arch-${dateStr.replace(/[^0-9]/g, '')}-${Date.now()}`,
                          date: dateStr,
                          timestamp: ts,
                          items: daySales,
                          purchaseInvoices: dayPurchases,
                          totalRevenue: rev,
                          totalExpenses: exp,
                          totalItems: daySales.length
                      });
                  }
              });

              return newHistory.sort((a, b) => b.timestamp - a.timestamp);
          });

          setSales([]);
          setPurchaseInvoices([]);
          alert('تم ترحيل البيانات وتصفير اليوم بنجاح!');
      } catch (error) {
          console.error('Archive Error:', error);
          alert('حدث خطأ أثناء الترحيل.');
      }
  }, [sales, purchaseInvoices]);

  const handleExportData = async () => {
    const backup = { 
      dailySales: sales, 
      dailyPurchaseInvoices: purchaseInvoices, 
      salesHistory: history, 
      products, 
      customers, 
      suppliers, 
      systemPassword,
      exportDate: new Date().toISOString() 
    };
    const jsonString = JSON.stringify(backup);
    try {
      const stream = new Blob([jsonString]).stream();
      const compressedStream = stream.pipeThrough(new (window as any).CompressionStream('gzip'));
      const response = new Response(compressedStream);
      const compressedBlob = await response.blob();
      const url = URL.createObjectURL(compressedBlob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `cookies-bakery-pro-${new Date().toLocaleDateString('en-GB').replace(/\//g, '-')}.bak`;
      link.click();
      URL.revokeObjectURL(url);
      lastBackupTimestamp.current = Date.now();
      setShowBackupReminder(false);
    } catch (err) {
      const blob = new Blob([jsonString], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `cookies-bakery-legacy-${new Date().toLocaleDateString('en-GB').replace(/\//g, '-')}.json`;
      link.click();
      URL.revokeObjectURL(url);
    }
  };

  const handleImportData = async (file: File) => {
    try {
      let jsonString = '';
      if (file.name.endsWith('.bak')) {
        const stream = file.stream();
        const decompressedStream = stream.pipeThrough(new (window as any).DecompressionStream('gzip'));
        const response = new Response(decompressedStream);
        jsonString = await response.text();
      } else {
        jsonString = await file.text();
      }
      const data = JSON.parse(jsonString);
      if (data.dailySales) setSales(data.dailySales);
      if (data.dailyPurchaseInvoices) setPurchaseInvoices(data.dailyPurchaseInvoices);
      if (data.salesHistory) setHistory(data.salesHistory);
      if (data.products) setProducts(data.products);
      if (data.customers) setCustomers(data.customers);
      if (data.suppliers) setSuppliers(data.suppliers);
      if (data.systemPassword) setSystemPassword(data.systemPassword);
      alert('تمت استعادة البيانات بنجاح.');
    } catch (err) { 
      alert('خطأ في استعادة البيانات.'); 
    }
  };

  if (isInitializing) return <WelcomeLoader onComplete={finalizeLogin} />;
  if (!isAuthenticated) return <Login onLogin={handleLoginSuccess} />;

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white relative">
      <Header 
        onOpenHistory={() => handleOpenProtected('history')} 
        onOpenDataManagement={() => handleOpenProtected('data')} 
        onOpenExpenses={() => handleOpenProtected('expenses')}
        onOpenAnalytics={() => handleOpenProtected('analytics')}
        onLogout={handleLogout}
        isOnline={isOnline} 
        lastSyncTime={lastSyncTime} 
        onManualSync={() => { setIsSyncing(true); setTimeout(() => setIsSyncing(false), 800); }} 
        onQuickBackup={handleExportData} 
        isSyncing={isSyncing}
        installPrompt={installPrompt}
        onInstall={handleInstall}
      />
      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl no-print">
        <Summary items={sales} onPreview={() => setInvoiceItems(sales)} systemPassword={systemPassword} />
        <POSInterface products={products} customers={customers} onCompleteOrder={completeOrder} onOpenProductManager={() => setModals(m => ({...m, products: true}))} onOpenCustomerManager={() => setModals(m => ({...m, customers: true}))} />
        <div className="mt-8">
            <SalesTable 
              items={sales} 
              onDeleteItem={(id: string) => setSales(s => s.filter(i => i.id !== id))} 
              onDeleteOrder={(oid: string) => setSales(s => s.filter(i => i.orderId !== oid))} 
              onPreviewInvoice={setInvoiceItems} 
              onUpdateItemPrice={(id: string, p: number) => setSales(s => s.map(i => i.id === id ? {...i, price: p} : i))} 
            />
        </div>
      </main>

      {showBackupReminder && (
        <div className="fixed bottom-6 right-6 left-6 md:left-auto md:w-80 bg-gray-800 border border-orange-500/50 p-5 rounded-[2rem] shadow-2xl z-[150] animate-fade-up flex flex-col gap-4 no-print">
            <div className="flex items-start gap-4">
                <div className="bg-orange-500/20 p-3 rounded-2xl text-orange-500 shrink-0"><AlertCircle size={24} /></div>
                <div className="flex-1">
                    <h4 className="text-white font-black text-sm">تذكير أمان البيانات</h4>
                    <p className="text-gray-400 text-[10px] font-bold mt-1 leading-relaxed">لقد مر وقت طويل منذ آخر نسخة احتياطية.</p>
                </div>
                <button onClick={() => setShowBackupReminder(false)} className="text-gray-500 hover:text-white"><X size={18} /></button>
            </div>
            <button onClick={handleExportData} className="w-full bg-orange-600 hover:bg-orange-500 text-white py-3 rounded-xl font-black text-xs flex items-center justify-center gap-2 transition-all"><Download size={14} /> نسخ مضغوط الآن</button>
        </div>
      )}

      <footer className="mt-12 py-8 border-t border-gray-800/50 text-center no-print">
         <button onClick={() => handleOpenProtected('full_reset')} className="text-gray-700 text-[10px] font-bold tracking-widest uppercase">نظام مبيعات كوكيز v2.6 • 2026</button>
      </footer>
      <Suspense fallback={<ModalLoader />}>
        {modals.analytics && <AnalyticsModal history={history} currentSales={sales} currentPurchases={purchaseInvoices} onClose={() => setModals(m => ({ ...m, analytics: false }))} />}
        {modals.expenses && <ExpensesModal isOpen={modals.expenses} onClose={() => setModals(m => ({...m, expenses: false}))} currentPurchases={purchaseInvoices} archivedHistory={history} onAddInvoice={v => setPurchaseInvoices(p => [...p, v])} onUpdateInvoice={v => setPurchaseInvoices(p => p.map(inv => inv.id === v.id ? v : inv))} onDeleteInvoice={id => setPurchaseInvoices(p => p.filter(v => v.id !== id))} suppliers={suppliers} onAddSupplier={s => setSuppliers(p => [...p, {...s, id: Date.now().toString()}])} onDeleteSupplier={id => setSuppliers(p => p.filter(s => s.id !== id))} />}
        {modals.history && <HistoryModal history={history} currentSales={sales} onClose={() => setModals(m => ({...m, history: false}))} onClearHistory={() => handleOpenProtected('clear_all_history')} onPreviewInvoice={setInvoiceItems} onUpdateOrder={handleUpdateArchivedOrder} onDeleteArchivedOrder={handleDeleteArchivedOrder} onDeleteArchivedDay={handleDeleteArchivedDay} />}
        {modals.products && <ProductManager isOpen={modals.products} onClose={() => setModals(m => ({...m, products: false}))} products={products} onAddProduct={p => setProducts(s => [...s, {...p, id: Date.now().toString()}])} onUpdateProduct={handleUpdateProduct} onDeleteProduct={id => setProducts(s => s.filter(p => p.id !== id))} />}
        {modals.customers && <CustomerManager isOpen={modals.customers} onClose={() => setModals(m => ({...m, customers: false}))} customers={customers} onAddCustomer={c => setCustomers(s => [...s, {...c, id: Date.now().toString()}])} onDeleteCustomer={id => setCustomers(s => s.filter(c => c.id !== id))} />}
        {modals.data && <DataManagementModal onClose={() => setModals(m => ({...m, data: false}))} onExport={handleExportData} onImport={handleImportData} onArchiveDay={handleArchiveDay} systemPassword={systemPassword} setSystemPassword={setSystemPassword} />}
        {invoiceItems && <InvoiceModal items={invoiceItems} onClose={() => setInvoiceItems(null)} />}
      </Suspense>
      {showLock && (
        <div className="fixed inset-0 bg-black/90 z-[200] flex items-center justify-center p-4 backdrop-blur-sm no-print">
          <div className="bg-gray-800 border border-gray-700 p-6 rounded-3xl w-full max-w-xs shadow-2xl animate-fade-up relative">
            <button onClick={() => { setShowLock(null); setLockPass(''); setLockError(false); }} className="absolute top-4 left-4 text-gray-500 hover:text-white transition-colors"><X size={20} /></button>
            <div className="text-center mb-6">
                <div className="w-12 h-12 bg-[#FA8072]/20 rounded-full flex items-center justify-center mx-auto mb-3"><Loader2 className="text-[#FA8072] animate-pulse" size={24} /></div>
                <h3 className="text-white font-black text-lg">تأكيد الإجراء</h3>
                <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest mt-1">أدخل كلمة المرور للمتابعة</p>
            </div>
            <input type="password" value={lockPass} onChange={e => setLockPass(e.target.value)} placeholder="رمز الدخول" className={`w-full bg-gray-900 border ${lockError ? 'border-red-500' : 'border-gray-700'} text-white p-4 rounded-2xl mb-4 text-center outline-none focus:border-[#FA8072] text-xl tracking-widest`} autoFocus onKeyDown={e => e.key === 'Enter' && verifyLock()} />
            {lockError && <p className="text-red-500 text-[10px] text-center mb-4 font-bold animate-pulse">رمز الدخول غير صحيح!</p>}
            <button onClick={verifyLock} className="w-full bg-gradient-to-r from-[#FA8072] to-orange-600 text-white py-4 rounded-2xl font-black text-sm shadow-lg active:scale-95 transition-all">تأكيد الإجراء</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { X, ChevronDown, ChevronUp, ArrowRight, Folder, CalendarDays, ShoppingBag, Zap, Store, User, Filter, TrendingUp, PieChart, Info, Clock, Download, Search, Trash2, Edit3, Check, Save, Hash, Eraser, AlertCircle } from 'lucide-react';
import { ArchivedDay, SaleItem, SaleType } from '../types';

interface HistoryModalProps {
  history: ArchivedDay[];
  currentSales?: SaleItem[];
  onClose: () => void;
  onClearHistory: () => void;
  onPreviewInvoice: (items: SaleItem[]) => void;
  onUpdateOrder: (dayId: string, orderId: string, updatedItems: SaleItem[], newCustomerName?: string) => void;
  onDeleteArchivedOrder: (dayId: string, orderId: string) => void;
  onDeleteArchivedDay: (dayId: string) => void;
}

type NavStep = 'years' | 'months' | 'days';
type FilterType = 'all' | SaleType;
type TabMode = 'archive' | 'profit-report';

export const HistoryModal: React.FC<HistoryModalProps> = ({ 
  history, currentSales = [], onClose, onClearHistory, onPreviewInvoice, onUpdateOrder, onDeleteArchivedOrder, onDeleteArchivedDay 
}) => {
  const [tab, setTab] = useState<TabMode>('archive');
  const [step, setStep] = useState<NavStep>('years');
  const [selectedYear, setSelectedYear] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<number>(-1);
  const [expandedDayId, setExpandedDayId] = useState<string | null>(null);
  const [filterType, setFilterType] = useState<FilterType>('all');
  const [searchTerm, setSearchTerm] = useState('');

  const [editingOrderId, setEditingOrderId] = useState<string | null>(null);
  const [editCustomerName, setEditCustomerName] = useState('');
  const [editOrderItems, setEditOrderItems] = useState<SaleItem[]>([]);

  const fullHistory = useMemo(() => {
      const today = new Date();
      const todayStr = today.toLocaleDateString('ar-SY');

      const activeSalesEntry: ArchivedDay | null = currentSales.length > 0 ? {
          id: 'today-active',
          date: `${todayStr} (مباشر)`,
          timestamp: today.getTime(),
          totalRevenue: currentSales.reduce((s, i) => s + (i.price * i.quantity), 0),
          totalExpenses: 0,
          totalItems: currentSales.length,
          items: currentSales,
          purchaseInvoices: []
      } : null;

      return activeSalesEntry ? [activeSalesEntry, ...history] : history;
  }, [history, currentSales]);

  const profitReport = useMemo(() => {
    const report: Record<string, { today: number, month: number, year: number, total: number }> = {};
    const now = new Date();
    const currentYear = now.getFullYear();
    const currentMonth = now.getMonth();
    const todayStr = now.toLocaleDateString('ar-SY');

    fullHistory.forEach(day => {
        const d = new Date(day.timestamp);
        const isYear = d.getFullYear() === currentYear;
        const isMonth = isYear && d.getMonth() === currentMonth;
        const isToday = day.date.includes(todayStr);

        day.items.forEach(item => {
            const profitPerUnit = item.price - (item.costPrice || 0);
            const totalProfit = profitPerUnit * item.quantity;
            if (!report[item.name]) report[item.name] = { today: 0, month: 0, year: 0, total: 0 };
            report[item.name].total += totalProfit;
            if (isYear) report[item.name].year += totalProfit;
            if (isMonth) report[item.name].month += totalProfit;
            if (isToday) report[item.name].today += totalProfit;
        });
    });
    return Object.entries(report).sort((a, b) => b[1].total - a[1].total);
  }, [fullHistory]);

  const years = useMemo(() => {
    const uniqueYears = new Set<string>(fullHistory.map(day => new Date(day.timestamp).getFullYear().toString()));
    return Array.from(uniqueYears).sort((a, b) => b.localeCompare(a));
  }, [fullHistory]);

  const months = useMemo(() => {
    if (!selectedYear) return [];
    const uniqueMonths = new Set<number>(
      fullHistory.filter(day => new Date(day.timestamp).getFullYear().toString() === selectedYear).map(day => new Date(day.timestamp).getMonth())
    );
    return Array.from(uniqueMonths).sort((a, b) => b - a);
  }, [fullHistory, selectedYear]);

  const currentDaysData = useMemo(() => {
    if (!selectedYear || selectedMonth === -1) return [];
    return fullHistory.filter(day => {
      const d = new Date(day.timestamp);
      return d.getFullYear().toString() === selectedYear && d.getMonth() === selectedMonth;
    }).sort((a,b) => b.timestamp - a.timestamp);
  }, [fullHistory, selectedYear, selectedMonth]);

  const getMonthName = (monthIndex: number) => new Date(2000, monthIndex).toLocaleString('ar-SY', { month: 'long' });

  const groupItemsByOrder = (items: SaleItem[]) => {
      const orders: Record<string, SaleItem[]> = {};
      items.forEach(item => {
          if (!orders[item.orderId]) orders[item.orderId] = [];
          orders[item.orderId].push(item);
      });

      let orderList = Object.values(orders);

      if (searchTerm.trim()) {
        const term = searchTerm.toLowerCase();
        orderList = orderList.filter(order => 
          (order[0].customerName?.toLowerCase() || '').includes(term) ||
          order[0].orderId.includes(term) ||
          order[0].customerNumber.toString() === term ||
          order.some(item => item.name.toLowerCase().includes(term))
        );
      }

      return orderList.sort((a, b) => b[0].orderId.localeCompare(a[0].orderId));
  };

  const handleStartOrderEdit = (orderItems: SaleItem[]) => {
      setEditingOrderId(orderItems[0].orderId);
      setEditCustomerName(orderItems[0].customerName || '');
      setEditOrderItems([...orderItems]);
  };

  const handleEditItemChange = (itemId: string, field: 'price' | 'quantity', value: string) => {
      setEditOrderItems(prev => prev.map(item => {
          if (item.id === itemId) {
              return { ...item, [field]: parseFloat(value) || 0 };
          }
          return item;
      }));
  };

  const handleRemoveItemFromEdit = (itemId: string) => {
      if (editOrderItems.length <= 1) {
          alert("لا يمكن حذف آخر مادة في الفاتورة، يرجى حذف الفاتورة كاملة بدلاً من ذلك.");
          return;
      }
      setEditOrderItems(prev => prev.filter(it => it.id !== itemId));
  };

  const handleSaveOrderEdit = (dayId: string) => {
      if (!editingOrderId) return;
      onUpdateOrder(dayId, editingOrderId, editOrderItems, editCustomerName);
      setEditingOrderId(null);
  };

  const renderArchive = () => {
    if (step === 'years') return (
        <div className="flex flex-col gap-6 animate-fade-up h-full">
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
                {years.length > 0 ? years.map(year => (
                    <button key={year} onClick={() => { setSelectedYear(year); setStep('months'); }} className="bg-gray-700/50 hover:bg-gray-600 border border-gray-600 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                        <Folder size={48} className="text-[#FA8072] group-hover:scale-110 transition-transform" />
                        <span className="text-xl font-black text-white">{year}</span>
                    </button>
                )) : (
                  <div className="col-span-full py-20 text-center flex flex-col items-center gap-4">
                      <div className="bg-gray-700/30 p-6 rounded-full"><Zap size={48} className="text-gray-600" /></div>
                      <p className="text-gray-500 font-bold">لا توجد عمليات بيع مؤرشفة بعد</p>
                  </div>
                )}
            </div>

            {history.length > 0 && (
                <div className="mt-auto pt-6 border-t border-gray-700">
                    <button 
                        onClick={() => { if(window.confirm('خطر! هل أنت متأكد من مسح كافة سجلات المبيعات المؤرشفة تماماً؟ لا يمكن التراجع عن هذا الإجراء.')) onClearHistory(); }}
                        className="flex items-center justify-center gap-2 w-full py-4 rounded-2xl bg-red-600/10 hover:bg-red-600 text-red-500 hover:text-white transition-all font-black text-sm border border-red-600/20 group"
                    >
                        <Eraser size={18} className="group-hover:animate-bounce" />
                        مسح كافة السجلات التاريخية وتصفير الأرشيف
                    </button>
                </div>
            )}
        </div>
    );

    if (step === 'months') return (
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4 animate-fade-up">
            {months.map(monthIdx => (
                <button key={monthIdx} onClick={() => { setSelectedMonth(monthIdx); setStep('days'); }} className="bg-gray-700/50 hover:bg-gray-600 border border-gray-700 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                    <CalendarDays size={48} className="text-blue-400 group-hover:scale-110 transition-transform" />
                    <span className="text-xl font-bold text-white">{getMonthName(monthIdx)}</span>
                </button>
            ))}
        </div>
    );

    if (step === 'days') return (
        <div className="flex flex-col gap-4 animate-fade-up h-full">
            <div className="flex flex-col md:flex-row items-center gap-3 shrink-0">
                <div className="relative flex-1 w-full">
                    <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" size={16} />
                    <input 
                      type="text" 
                      value={searchTerm}
                      onChange={e => setSearchTerm(e.target.value)}
                      placeholder="بحث في الفواتير (اسم الزبون، مادة، رقم الفاتورة)..." 
                      className="w-full bg-gray-900 border border-gray-700 text-white rounded-xl pr-10 pl-4 py-2 text-xs focus:border-[#FA8072] outline-none" 
                    />
                </div>
                <div className="flex items-center gap-1 bg-gray-900 p-1 rounded-xl border border-gray-700 w-full md:w-auto">
                    <button onClick={() => setFilterType('all')} className={`flex-1 md:px-4 py-1.5 text-[10px] font-black rounded-lg transition-all ${filterType === 'all' ? 'bg-white text-black shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>الكل</button>
                    <button onClick={() => setFilterType('retail')} className={`flex-1 md:px-4 py-1.5 text-[10px] font-black rounded-lg transition-all ${filterType === 'retail' ? 'bg-blue-500 text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>مفرق</button>
                    <button onClick={() => setFilterType('wholesale')} className={`flex-1 md:px-4 py-1.5 text-[10px] font-black rounded-lg transition-all ${filterType === 'wholesale' ? 'bg-orange-500 text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>جملة</button>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto space-y-3 pr-1 custom-scrollbar">
                {currentDaysData.map(day => {
                    const filteredItems = day.items.filter(item => filterType === 'all' || item.saleType === filterType);
                    const groupedOrders = groupItemsByOrder(filteredItems);
                    if (groupedOrders.length === 0) return null;

                    const dayTotal = filteredItems.reduce((s, i) => s + (i.price * i.quantity), 0);
                    const isTodayActive = day.id === 'today-active';

                    return (
                        <div key={day.id} className={`rounded-xl border overflow-hidden shadow-sm transition-all ${isTodayActive ? 'border-orange-500/50 bg-orange-500/5' : 'border-gray-700 bg-gray-800'}`}>
                            <div className={`p-4 flex justify-between items-center ${isTodayActive ? 'bg-orange-500/10' : 'bg-gray-900/50'}`}>
                                <div onClick={() => setExpandedDayId(expandedDayId === day.id ? null : day.id)} className="flex items-center gap-3 cursor-pointer flex-grow">
                                    <div className="text-gray-500">{(expandedDayId === day.id || searchTerm) ? <ChevronUp size={18} /> : <ChevronDown size={18} />}</div>
                                    <span className={`font-bold ${isTodayActive ? 'text-orange-400' : 'text-white'}`}>{day.date}</span>
                                    {searchTerm && <span className="text-[10px] bg-blue-500/20 text-blue-400 px-2 py-0.5 rounded-full font-bold">{groupedOrders.length} نتيجة</span>}
                                </div>
                                <div className="flex items-center gap-4">
                                    <div className="flex flex-col items-end">
                                        <span className="font-black text-lg text-green-400">{dayTotal.toLocaleString()} <small className="text-[10px] text-gray-500 font-normal">ل.س</small></span>
                                        {day.totalExpenses > 0 && <span className="text-[10px] text-red-400 font-bold">مشتريات: {day.totalExpenses.toLocaleString()}</span>}
                                    </div>
                                    {!isTodayActive && (
                                        <button 
                                            onClick={() => { if(window.confirm(`هل أنت متأكد من حذف يوم ${day.date} بالكامل بجميع فواتيره؟`)) onDeleteArchivedDay(day.id); }}
                                            className="p-2 text-gray-600 hover:text-red-500 transition-colors"
                                            title="حذف اليوم بالكامل"
                                        >
                                            <Trash2 size={20} />
                                        </button>
                                    )}
                                </div>
                            </div>
                            {(expandedDayId === day.id || searchTerm) && (
                                <div className="p-4 bg-gray-900/30 border-t border-gray-700 animate-fade-up space-y-4">
                                    {groupedOrders.map((orderItems, oIdx) => {
                                        const first = orderItems[0];
                                        const isEditing = editingOrderId === first.orderId;
                                        const orderTotal = (isEditing ? editOrderItems : orderItems).reduce((s, i) => s + (i.price * i.quantity), 0);

                                        return (
                                            <div key={oIdx} className={`bg-gray-800/80 rounded-2xl border overflow-hidden shadow-inner transition-all ${isEditing ? 'border-[#FA8072] ring-2 ring-[#FA8072]/20' : 'border-gray-700'}`}>
                                                <div className={`p-3 flex justify-between items-center border-b ${isEditing ? 'bg-[#FA8072]/10 border-[#FA8072]/20' : 'bg-gray-900/50 border-gray-700/50'}`}>
                                                    <div className="flex items-center gap-2">
                                                        <div className="flex items-center gap-1.5 bg-black/40 px-2 py-0.5 rounded border border-gray-700" title="رقم الفاتورة">
                                                            <Hash size={10} className="text-[#FA8072]" />
                                                            <span className="text-xs font-black text-white tabular-nums">{first.customerNumber}</span>
                                                        </div>
                                                        {first.saleType === 'wholesale' ? <Store size={14} className="text-orange-400" /> : <User size={14} className="text-blue-400" />}

                                                        {isEditing ? (
                                                            <input 
                                                              type="text" 
                                                              value={editCustomerName} 
                                                              onChange={e => setEditCustomerName(e.target.value)}
                                                              className="bg-gray-900 border border-[#FA8072] text-white text-xs px-2 py-1 rounded-lg outline-none focus:ring-1 focus:ring-[#FA8072]"
                                                              placeholder="اسم الزبون..."
                                                            />
                                                        ) : (
                                                            <span className="text-white text-xs font-black">{first.customerName || 'زبون عام'}</span>
                                                        )}
                                                    </div>

                                                    <div className="flex items-center gap-3">
                                                        <div className="flex items-center gap-1 text-[9px] text-gray-500 font-bold"><Clock size={10} />{first.time}</div>
                                                        <span className="text-green-400 font-black text-sm">{orderTotal.toLocaleString()}</span>

                                                        <div className="flex gap-2">
                                                           {isEditing ? (
                                                               <>
                                                                 <button onClick={() => handleSaveOrderEdit(day.id)} className="bg-green-600 hover:bg-green-500 text-white p-1.5 rounded-lg flex items-center gap-1 transition-colors">
                                                                    <Save size={14} />
                                                                 </button>
                                                                 <button onClick={() => setEditingOrderId(null)} className="bg-gray-700 hover:bg-gray-600 text-white p-1.5 rounded-lg transition-colors">
                                                                    <X size={14} />
                                                                 </button>
                                                               </>
                                                           ) : (
                                                               <>
                                                                 <button onClick={() => onPreviewInvoice(orderItems)} className="text-gray-500 hover:text-white transition-colors" title="طباعة"><Download size={14}/></button>
                                                                 {!isTodayActive && (
                                                                   <button onClick={() => handleStartOrderEdit(orderItems)} className="text-gray-500 hover:text-[#FA8072] transition-colors" title="تعديل الفاتورة"><Edit3 size={14}/></button>
                                                                 )}
                                                                 <button 
                                                                    onClick={() => { if(window.confirm('هل أنت متأكد من حذف هذه الفاتورة من الأرشيف؟')){ onDeleteArchivedOrder(day.id, first.orderId); } }} 
                                                                    className="text-gray-500 hover:text-red-400 transition-all p-1.5 hover:bg-red-500/10 rounded-lg" 
                                                                    title="حذف الفاتورة"
                                                                 >
                                                                    <Trash2 size={14}/>
                                                                 </button>
                                                               </>
                                                           )}
                                                        </div>
                                                    </div>
                                                </div>
                                                <div className="p-2 space-y-1">
                                                    {(isEditing ? editOrderItems : orderItems).map((item, iIdx) => (
                                                        <div key={iIdx} className="flex justify-between items-center text-[10px] px-2 py-1.5 bg-gray-900/20 rounded group/row">
                                                            <div className="flex items-center gap-2 flex-1">
                                                                {isEditing && (
                                                                    <button onClick={() => handleRemoveItemFromEdit(item.id)} className="text-red-400/50 hover:text-red-500 p-1" title="حذف المادة من الفاتورة">
                                                                        <Trash2 size={10} />
                                                                    </button>
                                                                )}
                                                                <span className="text-gray-300 font-bold min-w-[80px]">{item.name}</span>
                                                                {isEditing && (
                                                                    <div className="flex items-center gap-2">
                                                                      <div className="flex flex-col">
                                                                        <label className="text-[7px] text-gray-500 font-bold uppercase">الكمية</label>
                                                                        <input 
                                                                          type="number" 
                                                                          value={item.quantity} 
                                                                          onChange={e => handleEditItemChange(item.id, 'quantity', e.target.value)} 
                                                                          className="w-14 bg-gray-950 border border-gray-700 text-white rounded px-1 text-center py-0.5 outline-none focus:border-[#FA8072]" 
                                                                        />
                                                                      </div>
                                                                      <div className="flex flex-col">
                                                                        <label className="text-[7px] text-gray-500 font-bold uppercase">السعر</label>
                                                                        <input 
                                                                          type="number" 
                                                                          value={item.price} 
                                                                          onChange={e => handleEditItemChange(item.id, 'price', e.target.value)} 
                                                                          className="w-20 bg-gray-950 border border-gray-700 text-[#FA8072] rounded px-1 text-center py-0.5 outline-none focus:border-[#FA8072]" 
                                                                        />
                                                                      </div>
                                                                    </div>
                                                                )}
                                                                {!isEditing && <span className="text-gray-500 font-normal">({item.quantity} {item.unitType === 'kg' ? 'كغ' : 'قطعة'})</span>}
                                                            </div>
                                                            <span className={`tabular-nums font-bold ${isEditing ? 'text-green-400' : 'text-gray-400'}`}>{(item.price * item.quantity).toLocaleString()}</span>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
  };

  const renderProfitReport = () => (
    <div className="flex flex-col h-full animate-fade-up">
        <div className="bg-blue-500/10 border border-blue-500/20 p-4 rounded-2xl mb-4 flex items-start gap-3">
            <span className="shrink-0 mt-0.5"><Info size={20} className="text-blue-400" /></span>
            <p className="text-xs text-gray-400 leading-relaxed font-bold">هذا التقرير يحلل صافي أرباح كل منتج بشكل منفصل بناءً على الفرق بين (سعر البيع) و (سعر التكلفة) المسجل عند وقت البيع.</p>
        </div>
        <div className="bg-gray-900 rounded-2xl border border-gray-700 overflow-hidden flex-1 flex flex-col">
            <div className="overflow-x-auto custom-scrollbar">
                <table className="w-full text-right text-xs">
                    <thead className="bg-gray-800 text-gray-400 font-black uppercase text-[9px] tracking-widest sticky top-0 z-10">
                        <tr>
                            <th className="p-4 border-b border-gray-700">اسم المنتج</th>
                            <th className="p-4 border-b border-gray-700 text-center">أرباح اليوم</th>
                            <th className="p-4 border-b border-gray-700 text-center">أرباح الشهر</th>
                            <th className="p-4 border-b border-gray-700 text-center">أرباح السنة</th>
                            <th className="p-4 border-b border-gray-700 text-center bg-[#FA8072]/10 text-[#FA8072]">إجمالي الربح</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-800">
                        {profitReport.map(([name, data], idx) => (
                            <tr key={idx} className="hover:bg-gray-800/50 transition-colors">
                                <td className="p-4 font-black text-white">{name}</td>
                                <td className="p-4 text-center tabular-nums text-gray-400">{data.today.toLocaleString()}</td>
                                <td className="p-4 text-center tabular-nums text-gray-400">{data.month.toLocaleString()}</td>
                                <td className="p-4 text-center tabular-nums text-gray-400">{data.year.toLocaleString()}</td>
                                <td className="p-4 text-center tabular-nums font-black text-green-400 bg-green-400/5">{data.total.toLocaleString()}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    </div>
  );

  return (
    <div className="fixed inset-0 bg-black/85 backdrop-blur-md z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-3xl w-full max-w-5xl shadow-2xl border border-gray-700 flex flex-col h-[85vh] overflow-hidden animate-fade-up">
        <div className="p-4 md:p-5 border-b border-gray-700 flex flex-col md:flex-row justify-between items-center bg-gray-900/50 gap-4 shrink-0">
            <div className="w-full md:w-auto order-3 md:order-1 flex justify-start">
                <button onClick={onClose} className="flex items-center gap-2 bg-gray-700 hover:bg-red-600 text-white px-4 py-2 rounded-xl text-xs font-bold transition-all shadow-lg active:scale-95 group">
                    <span>إغلاق</span>
                    <X size={18} className="group-hover:rotate-90 transition-transform" />
                </button>
            </div>
            <div className="flex items-center gap-1 bg-gray-950 p-1 rounded-xl border border-gray-700 w-full md:w-auto order-2">
                <button onClick={() => setTab('archive')} className={`flex-1 md:flex-none px-6 py-2 rounded-lg text-xs font-black flex items-center gap-2 transition-all ${tab === 'archive' ? 'bg-[#FA8072] text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}><Folder size={14} /> تصفح الأرشيف</button>
                <button onClick={() => setTab('profit-report')} className={`flex-1 md:flex-none px-6 py-2 rounded-lg text-xs font-black flex items-center gap-2 transition-all ${tab === 'profit-report' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}><PieChart size={14} /> تقرير الأرباح</button>
            </div>
            <div className="flex items-center gap-3 w-full md:w-auto order-1 md:order-3 justify-end">
                <h3 className="font-black text-lg md:text-xl text-white">أرشيف المبيعات</h3>
                {tab === 'archive' && step !== 'years' && (
                    <button onClick={() => { if (step === 'days') { setStep('months'); setSelectedMonth(-1); } else if (step === 'months') { setStep('years'); setSelectedYear(''); } }} className="bg-gray-700 hover:bg-[#FA8072] p-2 rounded-full text-white transition-colors shrink-0 shadow-lg"><ArrowRight size={20} /></button>
                )}
            </div>
        </div>
        <div className="p-6 flex-1 overflow-y-auto custom-scrollbar">{tab === 'archive' ? renderArchive() : renderProfitReport()}</div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Trash2, Search, User, Download, Store, Edit3, Receipt, Clock, Package, ChevronDown, ChevronUp, LayoutList, Hash, AlertTriangle } from 'lucide-react';
import { SaleItem } from '../types';

export const SalesTable: React.FC<any> = ({ items, onDeleteItem, onDeleteOrder, onPreviewInvoice, onUpdateItemPrice }) => {
  const [searchTerm, setSearchTerm] = useState<string>('');
  const [isExpanded, setIsExpanded] = useState(false);
  const [editingPriceId, setEditingPriceId] = useState<string | null>(null);
  const [tempPrice, setTempPrice] = useState<string>('');

  const groupedOrders = useMemo(() => {
    const groups: { [key: string]: SaleItem[] } = {};
    items.forEach((item: SaleItem) => {
        const key = item.orderId;
        if (!groups[key]) groups[key] = [];
        groups[key].push(item);
    });
    return Object.values(groups).sort((a, b) => b[0].orderId.localeCompare(a[0].orderId));
  }, [items]);

  const filteredOrders = useMemo(() => {
      const term = searchTerm.toLowerCase().trim();
      if (!term) {
          return isExpanded ? groupedOrders : groupedOrders.slice(0, 1);
      }
      return groupedOrders.filter(g => 
          (g[0].customerName?.toLowerCase() || '').includes(term) ||
          g[0].orderId.includes(term) ||
          g[0].customerNumber.toString() === term
      );
  }, [groupedOrders, searchTerm, isExpanded]);

  const savePrice = (itemId: string) => {
    const price = parseFloat(tempPrice);
    if (!isNaN(price) && onUpdateItemPrice) onUpdateItemPrice(itemId, price);
    setEditingPriceId(null);
  };

  const handleDeleteOrderWithConfirm = (orderId: string, customerName: string) => {
    if (window.confirm(`تنبيه: هل أنت متأكد من حذف فاتورة "${customerName || 'زبون عام'}" بالكامل من مبيعات اليوم؟\n\nلا يمكن التراجع عن هذا الإجراء.`)) {
      onDeleteOrder && onDeleteOrder(orderId);
    }
  };

  const handleDeleteItemWithConfirm = (itemId: string, itemName: string) => {
    if (window.confirm(`هل أنت متأكد من حذف مادة "${itemName}" من الفاتورة؟`)) {
      onDeleteItem(itemId);
    }
  };

  if (items.length === 0) return (
    <div className="p-16 text-center flex flex-col items-center gap-4 bg-gray-800/30 rounded-[2.5rem] border border-dashed border-gray-700">
        <Receipt size={48} className="text-gray-700" />
        <p className="text-gray-500 font-bold text-sm">لا توجد مبيعات نشطة حالياً.</p>
    </div>
  );

  return (
    <div className="space-y-4">
        <div className="flex flex-col md:flex-row gap-4 items-center justify-between no-print px-2">
            <div className="relative w-full md:max-w-xs">
                <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" size={16} />
                <input 
                  type="text" 
                  value={searchTerm} 
                  onChange={e => setSearchTerm(e.target.value)} 
                  placeholder="بحث باسم الزبون أو رقم الفاتورة..." 
                  className="w-full bg-gray-800 border border-gray-700 text-white rounded-xl pr-10 pl-4 py-2 text-xs outline-none focus:border-[#FA8072] transition-all shadow-lg" 
                />
            </div>
            {!searchTerm && groupedOrders.length > 1 && (
                <button 
                  onClick={() => setIsExpanded(!isExpanded)}
                  className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-lg ${isExpanded ? 'bg-gray-700 text-white' : 'bg-[#FA8072] text-white animate-pulse'}`}
                >
                    {isExpanded ? (
                        <><ChevronUp size={14} /> إخفاء الفواتير القديمة</>
                    ) : (
                        <><LayoutList size={14} /> عرض كافة فواتير اليوم ({groupedOrders.length})</>
                    )}
                </button>
            )}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {filteredOrders.map((group, index) => {
                const total = group.reduce((s, i) => s + (i.price * i.quantity), 0);
                const first = group[0];
                const isLatest = index === 0 && !searchTerm && !isExpanded;

                return (
                    <div 
                      key={first.orderId} 
                      className={`bg-gray-800 rounded-[2rem] border overflow-hidden shadow-2xl animate-fade-up flex flex-col transition-all group ${isLatest ? 'border-[#FA8072] ring-2 ring-[#FA8072]/20' : 'border-gray-700 opacity-90'}`}
                    >
                        <div className={`p-4 flex justify-between items-start border-b ${isLatest ? 'bg-[#FA8072]/5 border-[#FA8072]/20' : 'bg-gray-900/50 border-gray-700/50'}`}>
                            <div className="flex gap-3">
                                <div className={`p-2 rounded-xl ${first.saleType === 'wholesale' ? 'bg-orange-500/10 text-orange-400' : 'bg-blue-500/10 text-blue-400'}`}>
                                    {first.saleType === 'wholesale' ? <Store size={18} /> : <User size={18} />}
                                </div>
                                <div className="flex flex-col">
                                    <div className="flex items-center gap-2">
                                        <div className="flex items-center gap-1.5 bg-black/40 px-2 py-0.5 rounded border border-gray-700" title="رقم الفاتورة">
                                            <Hash size={10} className="text-[#FA8072]" />
                                            <span className="text-sm font-black text-white tabular-nums">{first.customerNumber}</span>
                                        </div>
                                        <span className="font-black text-white text-sm">{first.customerName || 'زبون عام'}</span>
                                        {isLatest && <span className="bg-[#FA8072] text-white text-[8px] px-1.5 py-0.5 rounded font-black uppercase">الأحدث</span>}
                                    </div>
                                    <div className="flex items-center gap-2 mt-1">
                                        <div className="flex items-center gap-1 text-[9px] text-gray-500 font-bold">
                                            <Clock size={10} /> {first.time}
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div className="flex flex-col items-end">
                                <span className={`font-black text-base tabular-nums ${isLatest ? 'text-[#FA8072]' : 'text-green-400'}`}>{total.toLocaleString('en-US')} <small className="text-[10px] opacity-70">ل.س</small></span>
                                <span className="text-[8px] text-gray-600 font-bold uppercase">إجمالي الفاتورة</span>
                            </div>
                        </div>

                        <div className="p-3 space-y-2">
                            {group.map(item => (
                                <div key={item.id} className="flex justify-between items-center text-xs p-2.5 bg-gray-900/30 rounded-xl border border-gray-700/30 hover:bg-gray-900/60 transition-colors">
                                    <div className="flex items-center gap-2">
                                        <div className="w-1 h-1 rounded-full bg-gray-600"></div>
                                        <div className="flex flex-col">
                                            <span className="text-gray-200 font-bold text-[11px]">{item.name}</span>
                                            <span className="text-[9px] text-gray-500">الكمية: <span className="text-gray-300">{item.quantity}</span> {item.unitType === 'kg' ? 'كغ' : 'قطعة'}</span>
                                        </div>
                                    </div>

                                    <div className="flex items-center gap-3">
                                        <div className="flex flex-col items-end">
                                            {editingPriceId === item.id ? (
                                                <input 
                                                  type="number" 
                                                  value={tempPrice} 
                                                  onChange={e => setTempPrice(e.target.value)} 
                                                  onBlur={() => savePrice(item.id)} 
                                                  onKeyDown={e => e.key === 'Enter' && savePrice(item.id)}
                                                  className="w-14 bg-gray-950 border border-[#FA8072] text-white rounded px-1 text-center text-[10px] outline-none" 
                                                  autoFocus 
                                                />
                                            ) : (
                                                <div className="flex items-center gap-1 cursor-pointer group/price" onClick={() => { setEditingPriceId(item.id); setTempPrice(item.price.toString()); }}>
                                                    <span className="text-[10px] text-gray-500 tabular-nums">{item.price.toLocaleString('en-US')} ل.س</span>
                                                    <Edit3 size={8} className="text-[#FA8072] opacity-0 group-hover/price:opacity-100" />
                                                </div>
                                            )}
                                            <span className="font-black text-white text-[11px] tabular-nums">{(item.price * item.quantity).toLocaleString('en-US')} ل.س</span>
                                        </div>
                                        <button onClick={() => handleDeleteItemWithConfirm(item.id, item.name)} className="text-gray-700 hover:text-red-500 transition-colors p-1"><Trash2 size={12} /></button>
                                    </div>
                                </div>
                            ))}
                        </div>

                        <div className="px-4 py-3 bg-gray-900/20 border-t border-gray-700/30 flex justify-between items-center no-print">
                            <button 
                              onClick={() => onPreviewInvoice(group)} 
                              className="flex items-center gap-1.5 text-[10px] font-black text-blue-400 hover:text-blue-300 transition-colors"
                            >
                                <Download size={12} /> تصدير
                            </button>
                            <button 
                              onClick={() => handleDeleteOrderWithConfirm(first.orderId, first.customerName || 'زبون عام')} 
                              className="flex items-center gap-1.5 text-[10px] font-black text-red-400/50 hover:text-red-400 transition-colors"
                            >
                                <Trash2 size={12} /> حذف الفاتورة
                            </button>
                        </div>
                    </div>
                );
            })}
        </div>

        {!searchTerm && !isExpanded && groupedOrders.length > 1 && (
            <div className="py-8 flex flex-col items-center justify-center gap-3 no-print">
                <div className="h-px w-24 bg-gray-800"></div>
                <p className="text-[10px] text-gray-500 font-bold uppercase tracking-[0.2em]">هناك {groupedOrders.length - 1} فواتير أخرى مخفية</p>
                <button 
                  onClick={() => setIsExpanded(true)}
                  className="text-[#FA8072] font-black text-xs hover:underline"
                >
                    عرض سجل اليوم بالكامل
                </button>
            </div>
        )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { X, ChevronDown, ChevronUp, ArrowRight, Folder, CalendarDays, ShoppingBag, Zap, Store, User, Filter, TrendingUp, PieChart, Info, Clock, Download, Search, Trash2, Edit3, Check, Save, Hash, Eraser, AlertCircle } from 'lucide-react';
import { ArchivedDay, SaleItem, SaleType } from '../types';

interface HistoryModalProps {
  history: ArchivedDay[];
  currentSales?: SaleItem[];
  onClose: () => void;
  onClearHistory: () => void;
  onPreviewInvoice: (items: SaleItem[]) => void;
  onUpdateOrder: (dayId: string, orderId: string, updatedItems: SaleItem[], newCustomerName?: string) => void;
  onDeleteArchivedOrder: (dayId: string, orderId: string) => void;
  onDeleteArchivedDay: (dayId: string) => void;
}

type NavStep = 'years' | 'months' | 'days';
type FilterType = 'all' | SaleType;
type TabMode = 'archive' | 'profit-report';

export const HistoryModal: React.FC<HistoryModalProps> = ({ 
  history, currentSales = [], onClose, onClearHistory, onPreviewInvoice, onUpdateOrder, onDeleteArchivedOrder, onDeleteArchivedDay 
}) => {
  const [tab, setTab] = useState<TabMode>('archive');
  const [step, setStep] = useState<NavStep>('years');
  const [selectedYear, setSelectedYear] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<number>(-1);
  const [expandedDayId, setExpandedDayId] = useState<string | null>(null);
  const [filterType, setFilterType] = useState<FilterType>('all');
  const [searchTerm, setSearchTerm] = useState('');

  const [editingOrderId, setEditingOrderId] = useState<string | null>(null);
  const [editCustomerName, setEditCustomerName] = useState('');
  const [editOrderItems, setEditOrderItems] = useState<SaleItem[]>([]);

  const fullHistory = useMemo(() => {
      const today = new Date();
      const todayStr = today.toLocaleDateString('ar-SY');

      const activeSalesEntry: ArchivedDay | null = currentSales.length > 0 ? {
          id: 'today-active',
          date: `${todayStr} (مباشر)`,
          timestamp: today.getTime(),
          totalRevenue: currentSales.reduce((s, i) => s + (i.price * i.quantity), 0),
          totalExpenses: 0,
          totalItems: currentSales.length,
          items: currentSales,
          purchaseInvoices: []
      } : null;

      return activeSalesEntry ? [activeSalesEntry, ...history] : history;
  }, [history, currentSales]);

  const profitReport = useMemo(() => {
    const report: Record<string, { today: number, month: number, year: number, total: number }> = {};
    const now = new Date();
    const currentYear = now.getFullYear();
    const currentMonth = now.getMonth();
    const todayStr = now.toLocaleDateString('ar-SY');

    fullHistory.forEach(day => {
        const d = new Date(day.timestamp);
        const isYear = d.getFullYear() === currentYear;
        const isMonth = isYear && d.getMonth() === currentMonth;
        const isToday = day.date.includes(todayStr);

        day.items.forEach(item => {
            const profitPerUnit = item.price - (item.costPrice || 0);
            const totalProfit = profitPerUnit * item.quantity;
            if (!report[item.name]) report[item.name] = { today: 0, month: 0, year: 0, total: 0 };
            report[item.name].total += totalProfit;
            if (isYear) report[item.name].year += totalProfit;
            if (isMonth) report[item.name].month += totalProfit;
            if (isToday) report[item.name].today += totalProfit;
        });
    });
    return Object.entries(report).sort((a, b) => b[1].total - a[1].total);
  }, [fullHistory]);

  const years = useMemo(() => {
    const uniqueYears = new Set<string>(fullHistory.map(day => new Date(day.timestamp).getFullYear().toString()));
    return Array.from(uniqueYears).sort((a, b) => b.localeCompare(a));
  }, [fullHistory]);

  const months = useMemo(() => {
    if (!selectedYear) return [];
    const uniqueMonths = new Set<number>(
      fullHistory.filter(day => new Date(day.timestamp).getFullYear().toString() === selectedYear).map(day => new Date(day.timestamp).getMonth())
    );
    return Array.from(uniqueMonths).sort((a, b) => b - a);
  }, [fullHistory, selectedYear]);

  const currentDaysData = useMemo(() => {
    if (!selectedYear || selectedMonth === -1) return [];
    return fullHistory.filter(day => {
      const d = new Date(day.timestamp);
      return d.getFullYear().toString() === selectedYear && d.getMonth() === selectedMonth;
    }).sort((a,b) => b.timestamp - a.timestamp);
  }, [fullHistory, selectedYear, selectedMonth]);

  const getMonthName = (monthIndex: number) => new Date(2000, monthIndex).toLocaleString('ar-SY', { month: 'long' });

  const groupItemsByOrder = (items: SaleItem[]) => {
      const orders: Record<string, SaleItem[]> = {};
      items.forEach(item => {
          if (!orders[item.orderId]) orders[item.orderId] = [];
          orders[item.orderId].push(item);
      });

      let orderList = Object.values(orders);

      if (searchTerm.trim()) {
        const term = searchTerm.toLowerCase();
        orderList = orderList.filter(order => 
          (order[0].customerName?.toLowerCase() || '').includes(term) ||
          order[0].orderId.includes(term) ||
          order[0].customerNumber.toString() === term ||
          order.some(item => item.name.toLowerCase().includes(term))
        );
      }

      return orderList.sort((a, b) => b[0].orderId.localeCompare(a[0].orderId));
  };

  const handleStartOrderEdit = (orderItems: SaleItem[]) => {
      setEditingOrderId(orderItems[0].orderId);
      setEditCustomerName(orderItems[0].customerName || '');
      setEditOrderItems([...orderItems]);
  };

  const handleEditItemChange = (itemId: string, field: 'price' | 'quantity', value: string) => {
      setEditOrderItems(prev => prev.map(item => {
          if (item.id === itemId) {
              return { ...item, [field]: parseFloat(value) || 0 };
          }
          return item;
      }));
  };

  const handleRemoveItemFromEdit = (itemId: string) => {
      if (editOrderItems.length <= 1) {
          alert("لا يمكن حذف آخر مادة في الفاتورة، يرجى حذف الفاتورة كاملة بدلاً من ذلك.");
          return;
      }
      setEditOrderItems(prev => prev.filter(it => it.id !== itemId));
  };

  const handleSaveOrderEdit = (dayId: string) => {
      if (!editingOrderId) return;
      onUpdateOrder(dayId, editingOrderId, editOrderItems, editCustomerName);
      setEditingOrderId(null);
  };

  const renderArchive = () => {
    if (step === 'years') return (
        <div className="flex flex-col gap-6 animate-fade-up h-full">
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
                {years.length > 0 ? years.map(year => (
                    <button key={year} onClick={() => { setSelectedYear(year); setStep('months'); }} className="bg-gray-700/50 hover:bg-gray-600 border border-gray-600 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                        <Folder size={48} className="text-[#FA8072] group-hover:scale-110 transition-transform" />
                        <span className="text-xl font-black text-white">{year}</span>
                    </button>
                )) : (
                  <div className="col-span-full py-20 text-center flex flex-col items-center gap-4">
                      <div className="bg-gray-700/30 p-6 rounded-full"><Zap size={48} className="text-gray-600" /></div>
                      <p className="text-gray-500 font-bold">لا توجد عمليات بيع مؤرشفة بعد</p>
                  </div>
                )}
            </div>

            {history.length > 0 && (
                <div className="mt-auto pt-6 border-t border-gray-700">
                    <button 
                        onClick={() => { if(window.confirm('خطر! هل أنت متأكد من مسح كافة سجلات المبيعات المؤرشفة تماماً؟ لا يمكن التراجع عن هذا الإجراء.')) onClearHistory(); }}
                        className="flex items-center justify-center gap-2 w-full py-4 rounded-2xl bg-red-600/10 hover:bg-red-600 text-red-500 hover:text-white transition-all font-black text-sm border border-red-600/20 group"
                    >
                        <Eraser size={18} className="group-hover:animate-bounce" />
                        مسح كافة السجلات التاريخية وتصفير الأرشيف
                    </button>
                </div>
            )}
        </div>
    );

    if (step === 'months') return (
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4 animate-fade-up">
            {months.map(monthIdx => (
                <button key={monthIdx} onClick={() => { setSelectedMonth(monthIdx); setStep('days'); }} className="bg-gray-700/50 hover:bg-gray-600 border border-gray-700 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                    <CalendarDays size={48} className="text-blue-400 group-hover:scale-110 transition-transform" />
                    <span className="text-xl font-bold text-white">{getMonthName(monthIdx)}</span>
                </button>
            ))}
        </div>
    );

    if (step === 'days') return (
        <div className="flex flex-col gap-4 animate-fade-up h-full">
            <div className="flex flex-col md:flex-row items-center gap-3 shrink-0">
                <div className="relative flex-1 w-full">
                    <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" size={16} />
                    <input 
                      type="text" 
                      value={searchTerm}
                      onChange={e => setSearchTerm(e.target.value)}
                      placeholder="بحث في الفواتير (اسم الزبون، مادة، رقم الفاتورة)..." 
                      className="w-full bg-gray-900 border border-gray-700 text-white rounded-xl pr-10 pl-4 py-2 text-xs focus:border-[#FA8072] outline-none" 
                    />
                </div>
                <div className="flex items-center gap-1 bg-gray-900 p-1 rounded-xl border border-gray-700 w-full md:w-auto">
                    <button onClick={() => setFilterType('all')} className={`flex-1 md:px-4 py-1.5 text-[10px] font-black rounded-lg transition-all ${filterType === 'all' ? 'bg-white text-black shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>الكل</button>
                    <button onClick={() => setFilterType('retail')} className={`flex-1 md:px-4 py-1.5 text-[10px] font-black rounded-lg transition-all ${filterType === 'retail' ? 'bg-blue-500 text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>مفرق</button>
                    <button onClick={() => setFilterType('wholesale')} className={`flex-1 md:px-4 py-1.5 text-[10px] font-black rounded-lg transition-all ${filterType === 'wholesale' ? 'bg-orange-500 text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>جملة</button>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto space-y-3 pr-1 custom-scrollbar">
                {currentDaysData.map(day => {
                    const filteredItems = day.items.filter(item => filterType === 'all' || item.saleType === filterType);
                    const groupedOrders = groupItemsByOrder(filteredItems);
                    if (groupedOrders.length === 0) return null;

                    const dayTotal = filteredItems.reduce((s, i) => s + (i.price * i.quantity), 0);
                    const isTodayActive = day.id === 'today-active';

                    return (
                        <div key={day.id} className={`rounded-xl border overflow-hidden shadow-sm transition-all ${isTodayActive ? 'border-orange-500/50 bg-orange-500/5' : 'border-gray-700 bg-gray-800'}`}>
                            <div className={`p-4 flex justify-between items-center ${isTodayActive ? 'bg-orange-500/10' : 'bg-gray-900/50'}`}>
                                <div onClick={() => setExpandedDayId(expandedDayId === day.id ? null : day.id)} className="flex items-center gap-3 cursor-pointer flex-grow">
                                    <div className="text-gray-500">{(expandedDayId === day.id || searchTerm) ? <ChevronUp size={18} /> : <ChevronDown size={18} />}</div>
                                    <span className={`font-bold ${isTodayActive ? 'text-orange-400' : 'text-white'}`}>{day.date}</span>
                                    {searchTerm && <span className="text-[10px] bg-blue-500/20 text-blue-400 px-2 py-0.5 rounded-full font-bold">{groupedOrders.length} نتيجة</span>}
                                </div>
                                <div className="flex items-center gap-4">
                                    <div className="flex flex-col items-end">
                                        <span className="font-black text-lg text-green-400">{dayTotal.toLocaleString()} <small className="text-[10px] text-gray-500 font-normal">ل.س</small></span>
                                        {day.totalExpenses > 0 && <span className="text-[10px] text-red-400 font-bold">مشتريات: {day.totalExpenses.toLocaleString()}</span>}
                                    </div>
                                    {!isTodayActive && (
                                        <button 
                                            onClick={() => { if(window.confirm(`تنبيه أمان: هل أنت متأكد من حذف يوم "${day.date}" بالكامل بجميع فواتيره؟ سيؤدي هذا لمسحه من الأرشيف نهائياً.`)) onDeleteArchivedDay(day.id); }}
                                            className="p-2 text-gray-600 hover:text-red-500 transition-colors"
                                            title="حذف اليوم بالكامل"
                                        >
                                            <Trash2 size={20} />
                                        </button>
                                    )}
                                </div>
                            </div>
                            {(expandedDayId === day.id || searchTerm) && (
                                <div className="p-4 bg-gray-900/30 border-t border-gray-700 animate-fade-up space-y-4">
                                    {groupedOrders.map((orderItems, oIdx) => {
                                        const first = orderItems[0];
                                        const isEditing = editingOrderId === first.orderId;
                                        const orderTotal = (isEditing ? editOrderItems : orderItems).reduce((s, i) => s + (i.price * i.quantity), 0);

                                        return (
                                            <div key={oIdx} className={`bg-gray-800/80 rounded-2xl border overflow-hidden shadow-inner transition-all ${isEditing ? 'border-[#FA8072] ring-2 ring-[#FA8072]/20' : 'border-gray-700'}`}>
                                                <div className={`p-3 flex justify-between items-center border-b ${isEditing ? 'bg-[#FA8072]/10 border-[#FA8072]/20' : 'bg-gray-900/50 border-gray-700/50'}`}>
                                                    <div className="flex items-center gap-2">
                                                        <div className="flex items-center gap-1.5 bg-black/40 px-2 py-0.5 rounded border border-gray-700" title="رقم الفاتورة">
                                                            <Hash size={10} className="text-[#FA8072]" />
                                                            <span className="text-xs font-black text-white tabular-nums">{first.customerNumber}</span>
                                                        </div>
                                                        {first.saleType === 'wholesale' ? <Store size={14} className="text-orange-400" /> : <User size={14} className="text-blue-400" />}

                                                        {isEditing ? (
                                                            <input 
                                                              type="text" 
                                                              value={editCustomerName} 
                                                              onChange={e => setEditCustomerName(e.target.value)}
                                                              className="bg-gray-900 border border-[#FA8072] text-white text-xs px-2 py-1 rounded-lg outline-none focus:ring-1 focus:ring-[#FA8072]"
                                                              placeholder="اسم الزبون..."
                                                            />
                                                        ) : (
                                                            <span className="text-white text-xs font-black">{first.customerName || 'زبون عام'}</span>
                                                        )}
                                                    </div>

                                                    <div className="flex items-center gap-3">
                                                        <div className="flex items-center gap-1 text-[9px] text-gray-500 font-bold"><Clock size={10} />{first.time}</div>
                                                        <span className="text-green-400 font-black text-sm">{orderTotal.toLocaleString()}</span>

                                                        <div className="flex gap-2">
                                                           {isEditing ? (
                                                               <>
                                                                 <button onClick={() => handleSaveOrderEdit(day.id)} className="bg-green-600 hover:bg-green-500 text-white p-1.5 rounded-lg flex items-center gap-1 transition-colors">
                                                                    <Save size={14} />
                                                                 </button>
                                                                 <button onClick={() => setEditingOrderId(null)} className="bg-gray-700 hover:bg-gray-600 text-white p-1.5 rounded-lg transition-colors">
                                                                    <X size={14} />
                                                                 </button>
                                                               </>
                                                           ) : (
                                                               <>
                                                                 <button onClick={() => onPreviewInvoice(orderItems)} className="text-gray-500 hover:text-white transition-colors" title="طباعة"><Download size={14}/></button>
                                                                 {!isTodayActive && (
                                                                   <button onClick={() => handleStartOrderEdit(orderItems)} className="text-gray-500 hover:text-[#FA8072] transition-colors" title="تعديل الفاتورة"><Edit3 size={14}/></button>
                                                                 )}
                                                                 <button 
                                                                    onClick={() => { if(window.confirm(`هل أنت متأكد من حذف هذه الفاتورة (رقم ${first.customerNumber}) نهائياً من الأرشيف؟`)){ onDeleteArchivedOrder(day.id, first.orderId); } }} 
                                                                    className="text-gray-500 hover:text-red-400 transition-all p-1.5 hover:bg-red-500/10 rounded-lg" 
                                                                    title="حذف الفاتورة"
                                                                 >
                                                                    <Trash2 size={14}/>
                                                                 </button>
                                                               </>
                                                           )}
                                                        </div>
                                                    </div>
                                                </div>
                                                <div className="p-2 space-y-1">
                                                    {(isEditing ? editOrderItems : orderItems).map((item, iIdx) => (
                                                        <div key={iIdx} className="flex justify-between items-center text-[10px] px-2 py-1.5 bg-gray-900/20 rounded group/row">
                                                            <div className="flex items-center gap-2 flex-1">
                                                                {isEditing && (
                                                                    <button onClick={() => handleRemoveItemFromEdit(item.id)} className="text-red-400/50 hover:text-red-500 p-1" title="حذف المادة من الفاتورة">
                                                                        <Trash2 size={10} />
                                                                    </button>
                                                                )}
                                                                <span className="text-gray-300 font-bold min-w-[80px]">{item.name}</span>
                                                                {isEditing && (
                                                                    <div className="flex items-center gap-2">
                                                                      <div className="flex flex-col">
                                                                        <label className="text-[7px] text-gray-500 font-bold uppercase">الكمية</label>
                                                                        <input 
                                                                          type="number" 
                                                                          value={item.quantity} 
                                                                          onChange={e => handleEditItemChange(item.id, 'quantity', e.target.value)} 
                                                                          className="w-14 bg-gray-950 border border-gray-700 text-white rounded px-1 text-center py-0.5 outline-none focus:border-[#FA8072]" 
                                                                        />
                                                                      </div>
                                                                      <div className="flex flex-col">
                                                                        <label className="text-[7px] text-gray-500 font-bold uppercase">السعر</label>
                                                                        <input 
                                                                          type="number" 
                                                                          value={item.price} 
                                                                          onChange={e => handleEditItemChange(item.id, 'price', e.target.value)} 
                                                                          className="w-20 bg-gray-950 border border-gray-700 text-[#FA8072] rounded px-1 text-center py-0.5 outline-none focus:border-[#FA8072]" 
                                                                        />
                                                                      </div>
                                                                    </div>
                                                                )}
                                                                {!isEditing && <span className="text-gray-500 font-normal">({item.quantity} {item.unitType === 'kg' ? 'كغ' : 'قطعة'})</span>}
                                                            </div>
                                                            <span className={`tabular-nums font-bold ${isEditing ? 'text-green-400' : 'text-gray-400'}`}>{(item.price * item.quantity).toLocaleString()}</span>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
  };

  const renderProfitReport = () => (
    <div className="flex flex-col h-full animate-fade-up">
        <div className="bg-blue-500/10 border border-blue-500/20 p-4 rounded-2xl mb-4 flex items-start gap-3">
            <span className="shrink-0 mt-0.5"><Info size={20} className="text-blue-400" /></span>
            <p className="text-xs text-gray-400 leading-relaxed font-bold">هذا التقرير يحلل صافي أرباح كل منتج بشكل منفصل بناءً على الفرق بين (سعر البيع) و (سعر التكلفة) المسجل عند وقت البيع.</p>
        </div>
        <div className="bg-gray-900 rounded-2xl border border-gray-700 overflow-hidden flex-1 flex flex-col">
            <div className="overflow-x-auto custom-scrollbar">
                <table className="w-full text-right text-xs">
                    <thead className="bg-gray-800 text-gray-400 font-black uppercase text-[9px] tracking-widest sticky top-0 z-10">
                        <tr>
                            <th className="p-4 border-b border-gray-700">اسم المنتج</th>
                            <th className="p-4 border-b border-gray-700 text-center">أرباح اليوم</th>
                            <th className="p-4 border-b border-gray-700 text-center">أرباح الشهر</th>
                            <th className="p-4 border-b border-gray-700 text-center">أرباح السنة</th>
                            <th className="p-4 border-b border-gray-700 text-center bg-[#FA8072]/10 text-[#FA8072]">إجمالي الربح</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-800">
                        {profitReport.map(([name, data], idx) => (
                            <tr key={idx} className="hover:bg-gray-800/50 transition-colors">
                                <td className="p-4 font-black text-white">{name}</td>
                                <td className="p-4 text-center tabular-nums text-gray-400">{data.today.toLocaleString()}</td>
                                <td className="p-4 text-center tabular-nums text-gray-400">{data.month.toLocaleString()}</td>
                                <td className="p-4 text-center tabular-nums text-gray-400">{data.year.toLocaleString()}</td>
                                <td className="p-4 text-center tabular-nums font-black text-green-400 bg-green-400/5">{data.total.toLocaleString()}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    </div>
  );

  return (
    <div className="fixed inset-0 bg-black/85 backdrop-blur-md z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-3xl w-full max-w-5xl shadow-2xl border border-gray-700 flex flex-col h-[85vh] overflow-hidden animate-fade-up">
        <div className="p-4 md:p-5 border-b border-gray-700 flex flex-col md:flex-row justify-between items-center bg-gray-900/50 gap-4 shrink-0">
            <div className="w-full md:w-auto order-3 md:order-1 flex justify-start">
                <button onClick={onClose} className="flex items-center gap-2 bg-gray-700 hover:bg-red-600 text-white px-4 py-2 rounded-xl text-xs font-bold transition-all shadow-lg active:scale-95 group">
                    <span>إغلاق</span>
                    <X size={18} className="group-hover:rotate-90 transition-transform" />
                </button>
            </div>
            <div className="flex items-center gap-1 bg-gray-950 p-1 rounded-xl border border-gray-700 w-full md:w-auto order-2">
                <button onClick={() => setTab('archive')} className={`flex-1 md:flex-none px-6 py-2 rounded-lg text-xs font-black flex items-center gap-2 transition-all ${tab === 'archive' ? 'bg-[#FA8072] text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}><Folder size={14} /> تصفح الأرشيف</button>
                <button onClick={() => setTab('profit-report')} className={`flex-1 md:flex-none px-6 py-2 rounded-lg text-xs font-black flex items-center gap-2 transition-all ${tab === 'profit-report' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}><PieChart size={14} /> تقرير الأرباح</button>
            </div>
            <div className="flex items-center gap-3 w-full md:w-auto order-1 md:order-3 justify-end">
                <h3 className="font-black text-lg md:text-xl text-white">أرشيف المبيعات</h3>
                {tab === 'archive' && step !== 'years' && (
                    <button onClick={() => { if (step === 'days') { setStep('months'); setSelectedMonth(-1); } else if (step === 'months') { setStep('years'); setSelectedYear(''); } }} className="bg-gray-700 hover:bg-[#FA8072] p-2 rounded-full text-white transition-colors shrink-0 shadow-lg"><ArrowRight size={20} /></button>
                )}
            </div>
        </div>
        <div className="p-6 flex-1 overflow-y-auto custom-scrollbar">{tab === 'archive' ? renderArchive() : renderProfitReport()}</div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { X, ChevronDown, ChevronUp, ArrowRight, Folder, CalendarDays, ShoppingBag, Zap, Store, User, Filter, TrendingUp, PieChart, Info, Clock, Download, Search, Trash2, Edit3, Check, Save, Hash, Eraser, AlertCircle } from 'lucide-react';
import { ArchivedDay, SaleItem, SaleType } from '../types';

interface HistoryModalProps {
  history: ArchivedDay[];
  currentSales?: SaleItem[];
  onClose: () => void;
  onPreviewInvoice: (items: SaleItem[]) => void;
  onUpdateOrder: (dayId: string, orderId: string, updatedItems: SaleItem[], newCustomerName?: string) => void;
  onDeleteArchivedOrder: (dayId: string, orderId: string) => void;
  onDeleteArchivedDay: (dayId: string) => void;
}

type NavStep = 'years' | 'months' | 'days';
type FilterType = 'all' | SaleType;
type TabMode = 'archive' | 'profit-report';

export const HistoryModal: React.FC<HistoryModalProps> = ({ 
  history, currentSales = [], onClose, onPreviewInvoice, onUpdateOrder, onDeleteArchivedOrder, onDeleteArchivedDay 
}) => {
  const [tab, setTab] = useState<TabMode>('archive');
  const [step, setStep] = useState<NavStep>('years');
  const [selectedYear, setSelectedYear] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<number>(-1);
  const [expandedDayId, setExpandedDayId] = useState<string | null>(null);
  const [filterType, setFilterType] = useState<FilterType>('all');
  const [searchTerm, setSearchTerm] = useState('');

  const [editingOrderId, setEditingOrderId] = useState<string | null>(null);
  const [editCustomerName, setEditCustomerName] = useState('');
  const [editOrderItems, setEditOrderItems] = useState<SaleItem[]>([]);

  const fullHistory = useMemo(() => {
      const today = new Date();
      const todayStr = today.toLocaleDateString('ar-SY');

      const activeSalesEntry: ArchivedDay | null = currentSales.length > 0 ? {
          id: 'today-active',
          date: `${todayStr} (مباشر)`,
          timestamp: today.getTime(),
          totalRevenue: currentSales.reduce((s, i) => s + (i.price * i.quantity), 0),
          totalExpenses: 0,
          totalItems: currentSales.length,
          items: currentSales,
          purchaseInvoices: []
      } : null;

      return activeSalesEntry ? [activeSalesEntry, ...history] : history;
  }, [history, currentSales]);

  const profitReport = useMemo(() => {
    const report: Record<string, { today: number, month: number, year: number, total: number }> = {};
    const now = new Date();
    const currentYear = now.getFullYear();
    const currentMonth = now.getMonth();
    const todayStr = now.toLocaleDateString('ar-SY');

    fullHistory.forEach(day => {
        const d = new Date(day.timestamp);
        const isYear = d.getFullYear() === currentYear;
        const isMonth = isYear && d.getMonth() === currentMonth;
        const isToday = day.date.includes(todayStr);

        day.items.forEach(item => {
            const profitPerUnit = item.price - (item.costPrice || 0);
            const totalProfit = profitPerUnit * item.quantity;
            if (!report[item.name]) report[item.name] = { today: 0, month: 0, year: 0, total: 0 };
            report[item.name].total += totalProfit;
            if (isYear) report[item.name].year += totalProfit;
            if (isMonth) report[item.name].month += totalProfit;
            if (isToday) report[item.name].today += totalProfit;
        });
    });
    return Object.entries(report).sort((a, b) => b[1].total - a[1].total);
  }, [fullHistory]);

  const years = useMemo(() => {
    const uniqueYears = new Set<string>(fullHistory.map(day => new Date(day.timestamp).getFullYear().toString()));
    return Array.from(uniqueYears).sort((a, b) => b.localeCompare(a));
  }, [fullHistory]);

  const months = useMemo(() => {
    if (!selectedYear) return [];
    const uniqueMonths = new Set<number>(
      fullHistory.filter(day => new Date(day.timestamp).getFullYear().toString() === selectedYear).map(day => new Date(day.timestamp).getMonth())
    );
    return Array.from(uniqueMonths).sort((a, b) => b - a);
  }, [fullHistory, selectedYear]);

  const currentDaysData = useMemo(() => {
    if (!selectedYear || selectedMonth === -1) return [];
    return fullHistory.filter(day => {
      const d = new Date(day.timestamp);
      return d.getFullYear().toString() === selectedYear && d.getMonth() === selectedMonth;
    }).sort((a,b) => b.timestamp - a.timestamp);
  }, [fullHistory, selectedYear, selectedMonth]);

  const getMonthName = (monthIndex: number) => new Date(2000, monthIndex).toLocaleString('ar-SY', { month: 'long' });

  const groupItemsByOrder = (items: SaleItem[]) => {
      const orders: Record<string, SaleItem[]> = {};
      items.forEach(item => {
          if (!orders[item.orderId]) orders[item.orderId] = [];
          orders[item.orderId].push(item);
      });

      let orderList = Object.values(orders);

      if (searchTerm.trim()) {
        const term = searchTerm.toLowerCase();
        orderList = orderList.filter(order => 
          (order[0].customerName?.toLowerCase() || '').includes(term) ||
          order[0].orderId.includes(term) ||
          order[0].customerNumber.toString() === term ||
          order.some(item => item.name.toLowerCase().includes(term))
        );
      }

      return orderList.sort((a, b) => b[0].orderId.localeCompare(a[0].orderId));
  };

  const handleStartOrderEdit = (orderItems: SaleItem[]) => {
      setEditingOrderId(orderItems[0].orderId);
      setEditCustomerName(orderItems[0].customerName || '');
      setEditOrderItems([...orderItems]);
  };

  const handleEditItemChange = (itemId: string, field: 'price' | 'quantity', value: string) => {
      setEditOrderItems(prev => prev.map(item => {
          if (item.id === itemId) {
              return { ...item, [field]: parseFloat(value) || 0 };
          }
          return item;
      }));
  };

  const handleRemoveItemFromEdit = (itemId: string) => {
      if (editOrderItems.length <= 1) {
          alert("لا يمكن حذف آخر مادة في الفاتورة، يرجى حذف الفاتورة كاملة بدلاً من ذلك.");
          return;
      }
      setEditOrderItems(prev => prev.filter(it => it.id !== itemId));
  };

  const handleSaveOrderEdit = (dayId: string) => {
      if (!editingOrderId) return;
      onUpdateOrder(dayId, editingOrderId, editOrderItems, editCustomerName);
      setEditingOrderId(null);
  };

  const renderArchive = () => {
    if (step === 'years') return (
        <div className="flex flex-col gap-6 animate-fade-up h-full">
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
                {years.length > 0 ? years.map(year => (
                    <button key={year} onClick={() => { setSelectedYear(year); setStep('months'); }} className="bg-gray-700/50 hover:bg-gray-600 border border-gray-600 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                        <Folder size={48} className="text-[#FA8072] group-hover:scale-110 transition-transform" />
                        <span className="text-xl font-black text-white">{year}</span>
                    </button>
                )) : (
                  <div className="col-span-full py-20 text-center flex flex-col items-center gap-4">
                      <div className="bg-gray-700/30 p-6 rounded-full"><Zap size={48} className="text-gray-600" /></div>
                      <p className="text-gray-500 font-bold">لا توجد عمليات بيع مؤرشفة بعد</p>
                  </div>
                )}
            </div>
        </div>
    );

    if (step === 'months') return (
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4 animate-fade-up">
            {months.map(monthIdx => (
                <button key={monthIdx} onClick={() => { setSelectedMonth(monthIdx); setStep('days'); }} className="bg-gray-700/50 hover:bg-gray-600 border border-gray-700 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                    <CalendarDays size={48} className="text-blue-400 group-hover:scale-110 transition-transform" />
                    <span className="text-xl font-bold text-white">{getMonthName(monthIdx)}</span>
                </button>
            ))}
        </div>
    );

    if (step === 'days') return (
        <div className="flex flex-col gap-4 animate-fade-up h-full">
            <div className="flex flex-col md:flex-row items-center gap-3 shrink-0">
                <div className="relative flex-1 w-full">
                    <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" size={16} />
                    <input 
                      type="text" 
                      value={searchTerm}
                      onChange={e => setSearchTerm(e.target.value)}
                      placeholder="بحث في الفواتير (اسم الزبون، مادة، رقم الفاتورة)..." 
                      className="w-full bg-gray-900 border border-gray-700 text-white rounded-xl pr-10 pl-4 py-2 text-xs focus:border-[#FA8072] outline-none" 
                    />
                </div>
                <div className="flex items-center gap-1 bg-gray-900 p-1 rounded-xl border border-gray-700 w-full md:w-auto">
                    <button onClick={() => setFilterType('all')} className={`flex-1 md:px-4 py-1.5 text-[10px] font-black rounded-lg transition-all ${filterType === 'all' ? 'bg-white text-black shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>الكل</button>
                    <button onClick={() => setFilterType('retail')} className={`flex-1 md:px-4 py-1.5 text-[10px] font-black rounded-lg transition-all ${filterType === 'retail' ? 'bg-blue-500 text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>مفرق</button>
                    <button onClick={() => setFilterType('wholesale')} className={`flex-1 md:px-4 py-1.5 text-[10px] font-black rounded-lg transition-all ${filterType === 'wholesale' ? 'bg-orange-500 text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>جملة</button>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto space-y-3 pr-1 custom-scrollbar">
                {currentDaysData.map(day => {
                    const filteredItems = day.items.filter(item => filterType === 'all' || item.saleType === filterType);
                    const groupedOrders = groupItemsByOrder(filteredItems);
                    if (groupedOrders.length === 0) return null;

                    const dayTotal = filteredItems.reduce((s, i) => s + (i.price * i.quantity), 0);
                    const isTodayActive = day.id === 'today-active';

                    return (
                        <div key={day.id} className={`rounded-xl border overflow-hidden shadow-sm transition-all ${isTodayActive ? 'border-orange-500/50 bg-orange-500/5' : 'border-gray-700 bg-gray-800'}`}>
                            <div className={`p-4 flex justify-between items-center ${isTodayActive ? 'bg-orange-500/10' : 'bg-gray-900/50'}`}>
                                <div onClick={() => setExpandedDayId(expandedDayId === day.id ? null : day.id)} className="flex items-center gap-3 cursor-pointer flex-grow">
                                    <div className="text-gray-500">{(expandedDayId === day.id || searchTerm) ? <ChevronUp size={18} /> : <ChevronDown size={18} />}</div>
                                    <span className={`font-bold ${isTodayActive ? 'text-orange-400' : 'text-white'}`}>{day.date}</span>
                                    {searchTerm && <span className="text-[10px] bg-blue-500/20 text-blue-400 px-2 py-0.5 rounded-full font-bold">{groupedOrders.length} نتيجة</span>}
                                </div>
                                <div className="flex items-center gap-4">
                                    <div className="flex flex-col items-end">
                                        <span className="font-black text-lg text-green-400">{dayTotal.toLocaleString()} <small className="text-[10px] text-gray-500 font-normal">ل.س</small></span>
                                        {day.totalExpenses > 0 && <span className="text-[10px] text-red-400 font-bold">مشتريات: {day.totalExpenses.toLocaleString()}</span>}
                                    </div>
                                    {!isTodayActive && (
                                        <button 
                                            onClick={() => { if(window.confirm(`تنبيه أمان: هل أنت متأكد من حذف يوم "${day.date}" بالكامل بجميع فواتيره؟ سيؤدي هذا لمسحه من الأرشيف نهائياً.`)) onDeleteArchivedDay(day.id); }}
                                            className="p-2 text-gray-600 hover:text-red-500 transition-colors"
                                            title="حذف اليوم بالكامل"
                                        >
                                            <Trash2 size={20} />
                                        </button>
                                    )}
                                </div>
                            </div>
                            {(expandedDayId === day.id || searchTerm) && (
                                <div className="p-4 bg-gray-900/30 border-t border-gray-700 animate-fade-up space-y-4">
                                    {groupedOrders.map((orderItems, oIdx) => {
                                        const first = orderItems[0];
                                        const isEditing = editingOrderId === first.orderId;
                                        const orderTotal = (isEditing ? editOrderItems : orderItems).reduce((s, i) => s + (i.price * i.quantity), 0);

                                        return (
                                            <div key={oIdx} className={`bg-gray-800/80 rounded-2xl border overflow-hidden shadow-inner transition-all ${isEditing ? 'border-[#FA8072] ring-2 ring-[#FA8072]/20' : 'border-gray-700'}`}>
                                                <div className={`p-3 flex justify-between items-center border-b ${isEditing ? 'bg-[#FA8072]/10 border-[#FA8072]/20' : 'bg-gray-900/50 border-gray-700/50'}`}>
                                                    <div className="flex items-center gap-2">
                                                        <div className="flex items-center gap-1.5 bg-black/40 px-2 py-0.5 rounded border border-gray-700" title="رقم الفاتورة">
                                                            <Hash size={10} className="text-[#FA8072]" />
                                                            <span className="text-xs font-black text-white tabular-nums">{first.customerNumber}</span>
                                                        </div>
                                                        {first.saleType === 'wholesale' ? <Store size={14} className="text-orange-400" /> : <User size={14} className="text-blue-400" />}

                                                        {isEditing ? (
                                                            <input 
                                                              type="text" 
                                                              value={editCustomerName} 
                                                              onChange={e => setEditCustomerName(e.target.value)}
                                                              className="bg-gray-900 border border-[#FA8072] text-white text-xs px-2 py-1 rounded-lg outline-none focus:ring-1 focus:ring-[#FA8072]"
                                                              placeholder="اسم الزبون..."
                                                            />
                                                        ) : (
                                                            <span className="text-white text-xs font-black">{first.customerName || 'زبون عام'}</span>
                                                        )}
                                                    </div>

                                                    <div className="flex items-center gap-3">
                                                        <div className="flex items-center gap-1 text-[9px] text-gray-500 font-bold"><Clock size={10} />{first.time}</div>
                                                        <span className="text-green-400 font-black text-sm">{orderTotal.toLocaleString()}</span>

                                                        <div className="flex gap-2">
                                                           {isEditing ? (
                                                               <>
                                                                 <button onClick={() => handleSaveOrderEdit(day.id)} className="bg-green-600 hover:bg-green-500 text-white p-1.5 rounded-lg flex items-center gap-1 transition-colors">
                                                                    <Save size={14} />
                                                                 </button>
                                                                 <button onClick={() => setEditingOrderId(null)} className="bg-gray-700 hover:bg-gray-600 text-white p-1.5 rounded-lg transition-colors">
                                                                    <X size={14} />
                                                                 </button>
                                                               </>
                                                           ) : (
                                                               <>
                                                                 <button onClick={() => onPreviewInvoice(orderItems)} className="text-gray-500 hover:text-white transition-colors" title="طباعة"><Download size={14}/></button>
                                                                 {!isTodayActive && (
                                                                   <button onClick={() => handleStartOrderEdit(orderItems)} className="text-gray-500 hover:text-[#FA8072] transition-colors" title="تعديل الفاتورة"><Edit3 size={14}/></button>
                                                                 )}
                                                                 <button 
                                                                    onClick={() => { if(window.confirm(`هل أنت متأكد من حذف هذه الفاتورة (رقم ${first.customerNumber}) نهائياً من الأرشيف؟`)){ onDeleteArchivedOrder(day.id, first.orderId); } }} 
                                                                    className="text-gray-500 hover:text-red-400 transition-all p-1.5 hover:bg-red-500/10 rounded-lg" 
                                                                    title="حذف الفاتورة"
                                                                 >
                                                                    <Trash2 size={14}/>
                                                                 </button>
                                                               </>
                                                           )}
                                                        </div>
                                                    </div>
                                                </div>
                                                <div className="p-2 space-y-1">
                                                    {(isEditing ? editOrderItems : orderItems).map((item, iIdx) => (
                                                        <div key={iIdx} className="flex justify-between items-center text-[10px] px-2 py-1.5 bg-gray-900/20 rounded group/row">
                                                            <div className="flex items-center gap-2 flex-1">
                                                                {isEditing && (
                                                                    <button onClick={() => handleRemoveItemFromEdit(item.id)} className="text-red-400/50 hover:text-red-500 p-1" title="حذف المادة من الفاتورة">
                                                                        <Trash2 size={10} />
                                                                    </button>
                                                                )}
                                                                <span className="text-gray-300 font-bold min-w-[80px]">{item.name}</span>
                                                                {isEditing && (
                                                                    <div className="flex items-center gap-2">
                                                                      <div className="flex flex-col">
                                                                        <label className="text-[7px] text-gray-500 font-bold uppercase">الكمية</label>
                                                                        <input 
                                                                          type="number" 
                                                                          value={item.quantity} 
                                                                          onChange={e => handleEditItemChange(item.id, 'quantity', e.target.value)} 
                                                                          className="w-14 bg-gray-950 border border-gray-700 text-white rounded px-1 text-center py-0.5 outline-none focus:border-[#FA8072]" 
                                                                        />
                                                                      </div>
                                                                      <div className="flex flex-col">
                                                                        <label className="text-[7px] text-gray-500 font-bold uppercase">السعر</label>
                                                                        <input 
                                                                          type="number" 
                                                                          value={item.price} 
                                                                          onChange={e => handleEditItemChange(item.id, 'price', e.target.value)} 
                                                                          className="w-20 bg-gray-950 border border-gray-700 text-[#FA8072] rounded px-1 text-center py-0.5 outline-none focus:border-[#FA8072]" 
                                                                        />
                                                                      </div>
                                                                    </div>
                                                                )}
                                                                {!isEditing && <span className="text-gray-500 font-normal">({item.quantity} {item.unitType === 'kg' ? 'كغ' : 'قطعة'})</span>}
                                                            </div>
                                                            <span className={`tabular-nums font-bold ${isEditing ? 'text-green-400' : 'text-gray-400'}`}>{(item.price * item.quantity).toLocaleString()}</span>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
  };

  const renderProfitReport = () => (
    <div className="flex flex-col h-full animate-fade-up">
        <div className="bg-blue-500/10 border border-blue-500/20 p-4 rounded-2xl mb-4 flex items-start gap-3">
            <span className="shrink-0 mt-0.5"><Info size={20} className="text-blue-400" /></span>
            <p className="text-xs text-gray-400 leading-relaxed font-bold">هذا التقرير يحلل صافي أرباح كل منتج بشكل منفصل بناءً على الفرق بين (سعر البيع) و (سعر التكلفة) المسجل عند وقت البيع.</p>
        </div>
        <div className="bg-gray-900 rounded-2xl border border-gray-700 overflow-hidden flex-1 flex flex-col">
            <div className="overflow-x-auto custom-scrollbar">
                <table className="w-full text-right text-xs">
                    <thead className="bg-gray-800 text-gray-400 font-black uppercase text-[9px] tracking-widest sticky top-0 z-10">
                        <tr>
                            <th className="p-4 border-b border-gray-700">اسم المنتج</th>
                            <th className="p-4 border-b border-gray-700 text-center">أرباح اليوم</th>
                            <th className="p-4 border-b border-gray-700 text-center">أرباح الشهر</th>
                            <th className="p-4 border-b border-gray-700 text-center">أرباح السنة</th>
                            <th className="p-4 border-b border-gray-700 text-center bg-[#FA8072]/10 text-[#FA8072]">إجمالي الربح</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-800">
                        {profitReport.map(([name, data], idx) => (
                            <tr key={idx} className="hover:bg-gray-800/50 transition-colors">
                                <td className="p-4 font-black text-white">{name}</td>
                                <td className="p-4 text-center tabular-nums text-gray-400">{data.today.toLocaleString()}</td>
                                <td className="p-4 text-center tabular-nums text-gray-400">{data.month.toLocaleString()}</td>
                                <td className="p-4 text-center tabular-nums text-gray-400">{data.year.toLocaleString()}</td>
                                <td className="p-4 text-center tabular-nums font-black text-green-400 bg-green-400/5">{data.total.toLocaleString()}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    </div>
  );

  return (
    <div className="fixed inset-0 bg-black/85 backdrop-blur-md z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-3xl w-full max-w-5xl shadow-2xl border border-gray-700 flex flex-col h-[85vh] overflow-hidden animate-fade-up">
        <div className="p-4 md:p-5 border-b border-gray-700 flex flex-col md:flex-row justify-between items-center bg-gray-900/50 gap-4 shrink-0">
            <div className="w-full md:w-auto order-3 md:order-1 flex justify-start">
                <button onClick={onClose} className="flex items-center gap-2 bg-gray-700 hover:bg-red-600 text-white px-4 py-2 rounded-xl text-xs font-bold transition-all shadow-lg active:scale-95 group">
                    <span>إغلاق</span>
                    <X size={18} className="group-hover:rotate-90 transition-transform" />
                </button>
            </div>
            <div className="flex items-center gap-1 bg-gray-950 p-1 rounded-xl border border-gray-700 w-full md:w-auto order-2">
                <button onClick={() => setTab('archive')} className={`flex-1 md:flex-none px-6 py-2 rounded-lg text-xs font-black flex items-center gap-2 transition-all ${tab === 'archive' ? 'bg-[#FA8072] text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}><Folder size={14} /> تصفح الأرشيف</button>
                <button onClick={() => setTab('profit-report')} className={`flex-1 md:flex-none px-6 py-2 rounded-lg text-xs font-black flex items-center gap-2 transition-all ${tab === 'profit-report' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}><PieChart size={14} /> تقرير الأرباح</button>
            </div>
            <div className="flex items-center gap-3 w-full md:w-auto order-1 md:order-3 justify-end">
                <h3 className="font-black text-lg md:text-xl text-white">أرشيف المبيعات</h3>
                {tab === 'archive' && step !== 'years' && (
                    <button onClick={() => { if (step === 'days') { setStep('months'); setSelectedMonth(-1); } else if (step === 'months') { setStep('years'); setSelectedYear(''); } }} className="bg-gray-700 hover:bg-[#FA8072] p-2 rounded-full text-white transition-colors shrink-0 shadow-lg"><ArrowRight size={20} /></button>
                )}
            </div>
        </div>
        <div className="p-6 flex-1 overflow-y-auto custom-scrollbar">{tab === 'archive' ? renderArchive() : renderProfitReport()}</div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, Suspense, useCallback, useRef } from 'react';
import { Header } from './components/Header';
import { POSInterface } from './components/RecipeGenerator';
import { SalesTable } from './components/Menu';
import { Summary } from './components/InfoBox';
import { Login } from './components/Login';
import { SaleItem, Product, ArchivedDay, SaleType, Customer, PurchaseInvoice, Supplier } from './types';
import { Loader2, X, ShieldCheck, Wifi, WifiOff, CloudDownload, CheckCircle2, AlertCircle, Download, AlertTriangle } from 'lucide-react';

const InvoiceModal = React.lazy(() => import('./components/InvoiceModal').then(m => ({ default: m.InvoiceModal })));
const ProductManager = React.lazy(() => import('./components/ProductManager').then(m => ({ default: m.ProductManager })));
const HistoryModal = React.lazy(() => import('./components/HistoryModal').then(m => ({ default: m.HistoryModal })));
const DataManagementModal = React.lazy(() => import('./components/DataManagementModal').then(m => ({ default: m.DataManagementModal })));
const CustomerManager = React.lazy(() => import('./components/CustomerManager').then(m => ({ default: m.CustomerManager })));
const ExpensesModal = React.lazy(() => import('./components/ExpensesModal').then(m => ({ default: m.ExpensesModal })));
const AnalyticsModal = React.lazy(() => import('./components/AnalyticsModal').then(m => ({ default: m.AnalyticsModal })));

const ModalLoader = () => <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center"><div className="bg-gray-800 p-4 rounded-full border border-gray-700"><Loader2 className="animate-spin text-[#FA8072]" size={32} /></div></div>;

const WelcomeLoader: React.FC<{ onComplete: () => void }> = ({ onComplete }) => {
  const [progress, setProgress] = useState(0);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    const timer = setInterval(() => {
      setProgress((prev) => {
        if (prev >= 100) {
          clearInterval(timer);
          setTimeout(onComplete, 500);
          return 100;
        }
        return prev + 5;
      });
    }, 100);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      clearInterval(timer);
    };
  }, [onComplete]);

  return (
    <div className="fixed inset-0 bg-gray-900 z-[300] flex flex-col items-center justify-center p-6 text-center overflow-hidden">
      <div className="absolute top-[-20%] left-[-10%] w-96 h-96 bg-[#FA8072]/10 rounded-full blur-[100px] animate-pulse"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-96 h-96 bg-blue-500/10 rounded-full blur-[120px] animate-pulse"></div>
      <div className="relative z-10 max-w-sm w-full">
        <div className="mb-8 relative">
           <div className="w-24 h-24 bg-gradient-to-tr from-[#FA8072] to-orange-600 rounded-[2rem] flex items-center justify-center mx-auto shadow-2xl shadow-orange-500/20 animate-bounce">
              <ShieldCheck className="text-white" size={48} />
           </div>
           {progress === 100 && (
             <div className="absolute -right-2 -bottom-2 bg-green-500 text-white p-1 rounded-full animate-fade-up">
                <CheckCircle2 size={24} />
             </div>
           )}
        </div>
        <h2 className="text-2xl font-black text-white mb-2 animate-fade-up">أهلاً بك في مخبز كوكيز</h2>
        <p className="text-gray-400 text-sm font-bold mb-8 h-10">
          {progress < 40 && "جاري الاتصال بقاعدة البيانات المحلية..."}
          {progress >= 40 && progress < 80 && "تأمين الملفات للعمل بوضعية الأوفلاين..."}
          {progress >= 80 && progress < 100 && "مزامنة البيانات السحابية..."}
          {progress === 100 && "النظام جاهز للعمل الآن"}
        </p>
        <div className="w-full bg-gray-800 h-3 rounded-full overflow-hidden border border-gray-700 mb-4 p-0.5">
          <div className="h-full bg-gradient-to-r from-[#FA8072] to-orange-500 rounded-full transition-all duration-300 ease-out shadow-lg shadow-orange-500/30" style={{ width: `${progress}%` }}></div>
        </div>
        <div className="flex justify-between items-center px-1">
          <div className="flex items-center gap-2">
             {isOnline ? (
               <Wifi size={14} className={progress < 100 ? "animate-pulse text-blue-400" : "text-green-500"} />
             ) : (
               <WifiOff size={14} className="text-red-500 animate-pulse" />
             )}
             <span className={`text-[10px] font-black uppercase tracking-widest ${isOnline ? 'text-gray-500' : 'text-red-500'}`}>
               {isOnline ? 'OFFLINE READY' : 'WORKING OFFLINE'}
             </span>
          </div>
          <span className="text-[#FA8072] font-black tabular-nums">{progress}%</span>
        </div>
      </div>
      <div className="absolute bottom-10 flex items-center gap-2 text-gray-600">
          <CloudDownload size={14} />
          <span className="text-[8px] font-black uppercase tracking-[0.3em]">Downloading System Assets</span>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => sessionStorage.getItem('isAuth') === 'true');
  const [isInitializing, setIsInitializing] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSyncTime, setLastSyncTime] = useState<Date>(() => new Date());
  const [showLock, setShowLock] = useState<{ target: string; data?: any } | null>(null);
  const [lockPass, setLockPass] = useState('');
  const [lockError, setLockError] = useState(false);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  // PWA Install Prompt State
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  useEffect(() => {
    const handleBeforeInstallPrompt = (e: any) => {
      e.preventDefault();
      setInstallPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    return () => window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
  }, []);

  const handleInstall = async () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    const { outcome } = await installPrompt.userChoice;
    if (outcome === 'accepted') {
      setInstallPrompt(null);
    }
  };

  const [systemPassword, setSystemPassword] = useState(() => localStorage.getItem('systemPassword') || '2026');

  const [showBackupReminder, setShowBackupReminder] = useState(false);
  const lastBackupTimestamp = useRef<number>(Date.now());

  const [sales, setSales] = useState<SaleItem[]>(() => JSON.parse(localStorage.getItem('dailySales') || '[]'));
  const [purchaseInvoices, setPurchaseInvoices] = useState<PurchaseInvoice[]>(() => JSON.parse(localStorage.getItem('dailyPurchaseInvoices') || '[]'));
  const [history, setHistory] = useState<ArchivedDay[]>(() => JSON.parse(localStorage.getItem('salesHistory') || '[]'));
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem('products') || '[]'));
  const [customers, setCustomers] = useState<Customer[]>(() => JSON.parse(localStorage.getItem('customers') || '[]'));
  const [suppliers, setSuppliers] = useState<Supplier[]>(() => JSON.parse(localStorage.getItem('suppliers') || '[]'));

  const [invoiceItems, setInvoiceItems] = useState<SaleItem[] | null>(null);
  const [modals, setModals] = useState({ products: false, customers: false, history: false, data: false, expenses: false, analytics: false });

  const handleLogout = () => {
    sessionStorage.removeItem('isAuth');
    setIsAuthenticated(false);
  };

  const handleOpenProtected = (target: string, data?: any) => {
    setShowLock({ target, data });
  };

  const completeOrder = useCallback((items: any[], customerName?: string, customerId?: string, saleType: SaleType = 'retail') => {
    const orderId = Date.now().toString();
    const time = new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: false });
    const todayDate = new Date().toLocaleDateString('en-US');

    const activeTodaySales = sales.filter(s => s.date === todayDate);
    const activeMax = activeTodaySales.length > 0 
      ? Math.max(...activeTodaySales.map(s => s.customerNumber)) 
      : 0;

    const archivedToday = history.find(h => h.date === todayDate);
    const archivedMax = (archivedToday && archivedToday.items.length > 0)
      ? Math.max(...archivedToday.items.map(s => s.customerNumber))
      : 0;

    const nextCustomerNumber = Math.max(activeMax, archivedMax) + 1;

    const newItems: SaleItem[] = items.map(item => ({
      ...item,
      id: Math.random().toString(36).substr(2, 9),
      orderId,
      customerNumber: nextCustomerNumber,
      customerName,
      customerId,
      saleType,
      time,
      date: todayDate
    }));

    setSales(prev => [...prev, ...newItems]);
    setInvoiceItems(newItems);
  }, [sales, history]);

  const handleUpdateProduct = (id: string, updatedProduct: Partial<Product>) => {
    setProducts(prev => prev.map(p => p.id === id ? { ...p, ...updatedProduct } : p));
  };

  const handleUpdateArchivedOrder = (dayId: string, orderId: string, updatedItems: SaleItem[], newCustomerName?: string) => {
    setHistory(prev => prev.map(day => {
      if (day.id === dayId) {
        const otherItems = day.items.filter(item => item.orderId !== orderId);
        const finalItems = [...otherItems, ...updatedItems.map(it => ({ ...it, customerName: newCustomerName || it.customerName }))];
        return {
          ...day,
          items: finalItems,
          totalRevenue: finalItems.reduce((s, i) => s + (i.price * i.quantity), 0),
          totalItems: finalItems.length
        };
      }
      return day;
    }));
  };

  const handleDeleteArchivedOrder = (dayId: string, orderId: string) => {
    setHistory(prev => {
      const updated = prev.map(day => {
        if (day.id === dayId) {
          const finalItems = day.items.filter(item => item.orderId !== orderId);
          return {
            ...day,
            items: finalItems,
            totalRevenue: finalItems.reduce((s, i) => s + (i.price * i.quantity), 0),
            totalItems: finalItems.length
          };
        }
        return day;
      });
      return updated.filter(day => day.items.length > 0 || (day.purchaseInvoices && day.purchaseInvoices.length > 0));
    });
  };

  const handleDeleteArchivedDay = (dayId: string) => {
    setHistory(prev => prev.filter(day => day.id !== dayId));
  };

  const handleLoginSuccess = () => {
    sessionStorage.setItem('isAuth', 'true');
    setIsInitializing(true);
  };

  const finalizeLogin = () => {
    setIsInitializing(false);
    setIsAuthenticated(true);
  };

  useEffect(() => {
    if (!isAuthenticated) return;
    const CHECK_INTERVAL = 60 * 1000; 
    const REMINDER_INTERVAL = 60 * 60 * 1000; 
    const intervalId = setInterval(() => {
      const now = Date.now();
      if (now - lastBackupTimestamp.current >= REMINDER_INTERVAL) {
        setShowBackupReminder(true);
      }
    }, CHECK_INTERVAL);
    return () => clearInterval(intervalId);
  }, [isAuthenticated]);

  useEffect(() => {
    localStorage.setItem('dailySales', JSON.stringify(sales));
    localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(purchaseInvoices));
    localStorage.setItem('salesHistory', JSON.stringify(history));
    localStorage.setItem('products', JSON.stringify(products));
    localStorage.setItem('customers', JSON.stringify(customers));
    localStorage.setItem('suppliers', JSON.stringify(suppliers));
    localStorage.setItem('systemPassword', systemPassword);
    setLastSyncTime(new Date());
  }, [sales, purchaseInvoices, history, products, customers, suppliers, systemPassword]);

  const verifyLock = () => {
    if (lockPass === systemPassword) {
      if (showLock?.target === 'full_reset') {
          localStorage.clear();
          window.location.reload();
      } else if (showLock?.target === 'clear_all_history') {
          setHistory([]);
      } else if (showLock) {
          setModals(m => ({ ...m, [showLock.target]: true }));
      }
      setShowLock(null);
      setLockPass('');
      setLockError(false);
    } else {
      setLockError(true);
    }
  };

  const handleArchiveDay = useCallback(() => {
      if (sales.length === 0 && purchaseInvoices.length === 0) {
          alert('لا توجد عمليات مبيعات أو مشتريات نشطة حالياً لترحيلها.');
          return;
      }

      const confirmed = window.confirm('هل أنت متأكد من ترحيل المبيعات للأرشيف وتصفير اليوم؟ \n\nسيتم توزيع كل فاتورة حسب تاريخها الأصلي في السجلات التاريخية.');
      if (!confirmed) return;

      try {
          const currentSales = [...sales];
          const currentPurchases = [...purchaseInvoices];

          const salesMap = new Map<string, SaleItem[]>();
          currentSales.forEach(s => {
              const d = s.date;
              if (!salesMap.has(d)) salesMap.set(d, []);
              salesMap.get(d)!.push(s);
          });

          const purchaseMap = new Map<string, PurchaseInvoice[]>();
          currentPurchases.forEach(p => {
              const d = p.date;
              if (!purchaseMap.has(d)) purchaseMap.set(d, []);
              purchaseMap.get(d)!.push(p);
          });

          const allUniqueDates = Array.from(new Set([...salesMap.keys(), ...purchaseMap.keys()]));

          setHistory(prev => {
              const newHistory = [...prev];

              allUniqueDates.forEach(dateStr => {
                  const daySales = salesMap.get(dateStr) || [];
                  const dayPurchases = purchaseMap.get(dateStr) || [];

                  const rev = daySales.reduce((s, i) => s + (i.price * i.quantity), 0);
                  const exp = dayPurchases.reduce((s, i) => s + i.totalAmount, 0);

                  const existingIdx = newHistory.findIndex(h => h.date === dateStr);

                  if (existingIdx !== -1) {
                      newHistory[existingIdx] = {
                          ...newHistory[existingIdx],
                          items: [...newHistory[existingIdx].items, ...daySales],
                          purchaseInvoices: [...(newHistory[existingIdx].purchaseInvoices || []), ...dayPurchases],
                          totalRevenue: newHistory[existingIdx].totalRevenue + rev,
                          totalExpenses: newHistory[existingIdx].totalExpenses + exp,
                          totalItems: newHistory[existingIdx].totalItems + daySales.length
                      };
                  } else {
                      const refItem = daySales[0];
                      const ts = refItem ? parseInt(refItem.orderId) : Date.now();

                      newHistory.push({
                          id: `arch-${dateStr.replace(/[^0-9]/g, '')}-${Date.now()}`,
                          date: dateStr,
                          timestamp: ts,
                          items: daySales,
                          purchaseInvoices: dayPurchases,
                          totalRevenue: rev,
                          totalExpenses: exp,
                          totalItems: daySales.length
                      });
                  }
              });

              return newHistory.sort((a, b) => b.timestamp - a.timestamp);
          });

          setSales([]);
          setPurchaseInvoices([]);
          alert('تم ترحيل البيانات وتصفير اليوم بنجاح!');
      } catch (error) {
          console.error('Archive Error:', error);
          alert('حدث خطأ أثناء الترحيل.');
      }
  }, [sales, purchaseInvoices]);

  const handleExportData = async () => {
    const backup = { 
      dailySales: sales, 
      dailyPurchaseInvoices: purchaseInvoices, 
      salesHistory: history, 
      products, 
      customers, 
      suppliers, 
      systemPassword,
      exportDate: new Date().toISOString() 
    };
    const jsonString = JSON.stringify(backup);
    try {
      const stream = new Blob([jsonString]).stream();
      const compressedStream = stream.pipeThrough(new (window as any).CompressionStream('gzip'));
      const response = new Response(compressedStream);
      const compressedBlob = await response.blob();
      const url = URL.createObjectURL(compressedBlob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `cookies-bakery-pro-${new Date().toLocaleDateString('en-GB').replace(/\//g, '-')}.bak`;
      link.click();
      URL.revokeObjectURL(url);
      lastBackupTimestamp.current = Date.now();
      setShowBackupReminder(false);
    } catch (err) {
      const blob = new Blob([jsonString], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `cookies-bakery-legacy-${new Date().toLocaleDateString('en-GB').replace(/\//g, '-')}.json`;
      link.click();
      URL.revokeObjectURL(url);
    }
  };

  const handleImportData = async (file: File) => {
    try {
      let jsonString = '';
      if (file.name.endsWith('.bak')) {
        const stream = file.stream();
        const decompressedStream = stream.pipeThrough(new (window as any).DecompressionStream('gzip'));
        const response = new Response(decompressedStream);
        jsonString = await response.text();
      } else {
        jsonString = await file.text();
      }
      const data = JSON.parse(jsonString);
      if (data.dailySales) setSales(data.dailySales);
      if (data.dailyPurchaseInvoices) setPurchaseInvoices(data.dailyPurchaseInvoices);
      if (data.salesHistory) setHistory(data.salesHistory);
      if (data.products) setProducts(data.products);
      if (data.customers) setCustomers(data.customers);
      if (data.suppliers) setSuppliers(data.suppliers);
      if (data.systemPassword) setSystemPassword(data.systemPassword);
      alert('تمت استعادة البيانات بنجاح.');
    } catch (err) { 
      alert('خطأ في استعادة البيانات.'); 
    }
  };

  if (isInitializing) return <WelcomeLoader onComplete={finalizeLogin} />;
  if (!isAuthenticated) return <Login onLogin={handleLoginSuccess} />;

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white relative">
      <Header 
        onOpenHistory={() => handleOpenProtected('history')} 
        onOpenDataManagement={() => handleOpenProtected('data')} 
        onOpenExpenses={() => handleOpenProtected('expenses')}
        onOpenAnalytics={() => handleOpenProtected('analytics')}
        onLogout={handleLogout}
        isOnline={isOnline} 
        lastSyncTime={lastSyncTime} 
        onManualSync={() => { setIsSyncing(true); setTimeout(() => setIsSyncing(false), 800); }} 
        onQuickBackup={handleExportData} 
        isSyncing={isSyncing}
        installPrompt={installPrompt}
        onInstall={handleInstall}
      />
      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl no-print">
        <Summary items={sales} onPreview={() => setInvoiceItems(sales)} systemPassword={systemPassword} />
        <POSInterface products={products} customers={customers} onCompleteOrder={completeOrder} onOpenProductManager={() => setModals(m => ({...m, products: true}))} onOpenCustomerManager={() => setModals(m => ({...m, customers: true}))} />
        <div className="mt-8">
            <SalesTable 
              items={sales} 
              onDeleteItem={(id: string) => setSales(s => s.filter(i => i.id !== id))} 
              onDeleteOrder={(oid: string) => setSales(s => s.filter(i => i.orderId !== oid))} 
              onPreviewInvoice={setInvoiceItems} 
              onUpdateItemPrice={(id: string, p: number) => setSales(s => s.map(i => i.id === id ? {...i, price: p} : i))} 
            />
        </div>
      </main>

      {showBackupReminder && (
        <div className="fixed bottom-6 right-6 left-6 md:left-auto md:w-80 bg-gray-800 border border-orange-500/50 p-5 rounded-[2rem] shadow-2xl z-[150] animate-fade-up flex flex-col gap-4 no-print">
            <div className="flex items-start gap-4">
                <div className="bg-orange-500/20 p-3 rounded-2xl text-orange-500 shrink-0"><AlertCircle size={24} /></div>
                <div className="flex-1">
                    <h4 className="text-white font-black text-sm">تذكير أمان البيانات</h4>
                    <p className="text-gray-400 text-[10px] font-bold mt-1 leading-relaxed">لقد مر وقت طويل منذ آخر نسخة احتياطية.</p>
                </div>
                <button onClick={() => setShowBackupReminder(false)} className="text-gray-500 hover:text-white"><X size={18} /></button>
            </div>
            <button onClick={handleExportData} className="w-full bg-orange-600 hover:bg-orange-500 text-white py-3 rounded-xl font-black text-xs flex items-center justify-center gap-2 transition-all"><Download size={14} /> نسخ مضغوط الآن</button>
        </div>
      )}

      <footer className="mt-12 py-8 border-t border-gray-800/50 text-center no-print">
         <button onClick={() => handleOpenProtected('full_reset')} className="text-gray-700 text-[10px] font-bold tracking-widest uppercase">نظام مبيعات كوكيز v2.6 • 2026</button>
      </footer>
      <Suspense fallback={<ModalLoader />}>
        {modals.analytics && <AnalyticsModal history={history} currentSales={sales} currentPurchases={purchaseInvoices} onClose={() => setModals(m => ({ ...m, analytics: false }))} />}
        {modals.expenses && <ExpensesModal isOpen={modals.expenses} onClose={() => setModals(m => ({...m, expenses: false}))} currentPurchases={purchaseInvoices} archivedHistory={history} onAddInvoice={v => setPurchaseInvoices(p => [...p, v])} onUpdateInvoice={v => setPurchaseInvoices(p => p.map(inv => inv.id === v.id ? v : inv))} onDeleteInvoice={id => setPurchaseInvoices(p => p.filter(v => v.id !== id))} suppliers={suppliers} onAddSupplier={s => setSuppliers(p => [...p, {...s, id: Date.now().toString()}])} onDeleteSupplier={id => setSuppliers(p => p.filter(s => s.id !== id))} />}
        {modals.history && <HistoryModal history={history} currentSales={sales} onClose={() => setModals(m => ({...m, history: false}))} onPreviewInvoice={setInvoiceItems} onUpdateOrder={handleUpdateArchivedOrder} onDeleteArchivedOrder={handleDeleteArchivedOrder} onDeleteArchivedDay={handleDeleteArchivedDay} />}
        {modals.products && <ProductManager isOpen={modals.products} onClose={() => setModals(m => ({...m, products: false}))} products={products} onAddProduct={p => setProducts(s => [...s, {...p, id: Date.now().toString()}])} onUpdateProduct={handleUpdateProduct} onDeleteProduct={id => setProducts(s => s.filter(p => p.id !== id))} />}
        {modals.customers && <CustomerManager isOpen={modals.customers} onClose={() => setModals(m => ({...m, customers: false}))} customers={customers} onAddCustomer={c => setCustomers(s => [...s, {...c, id: Date.now().toString()}])} onDeleteCustomer={id => setCustomers(s => s.filter(c => c.id !== id))} />}
        {modals.data && <DataManagementModal onClose={() => setModals(m => ({...m, data: false}))} onExport={handleExportData} onImport={handleImportData} onArchiveDay={handleArchiveDay} systemPassword={systemPassword} setSystemPassword={setSystemPassword} />}
        {invoiceItems && <InvoiceModal items={invoiceItems} onClose={() => setInvoiceItems(null)} />}
      </Suspense>
      {showLock && (
        <div className="fixed inset-0 bg-black/90 z-[200] flex items-center justify-center p-4 backdrop-blur-sm no-print">
          <div className="bg-gray-800 border border-gray-700 p-6 rounded-3xl w-full max-w-xs shadow-2xl animate-fade-up relative">
            <button onClick={() => { setShowLock(null); setLockPass(''); setLockError(false); }} className="absolute top-4 left-4 text-gray-500 hover:text-white transition-colors"><X size={20} /></button>
            <div className="text-center mb-6">
                <div className="w-12 h-12 bg-[#FA8072]/20 rounded-full flex items-center justify-center mx-auto mb-3"><Loader2 className="text-[#FA8072] animate-pulse" size={24} /></div>
                <h3 className="text-white font-black text-lg">تأكيد الإجراء</h3>
                <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest mt-1">أدخل كلمة المرور للمتابعة</p>
            </div>
            <input type="password" value={lockPass} onChange={e => setLockPass(e.target.value)} placeholder="رمز الدخول" className={`w-full bg-gray-900 border ${lockError ? 'border-red-500' : 'border-gray-700'} text-white p-4 rounded-2xl mb-4 text-center outline-none focus:border-[#FA8072] text-xl tracking-widest`} autoFocus onKeyDown={e => e.key === 'Enter' && verifyLock()} />
            {lockError && <p className="text-red-500 text-[10px] text-center mb-4 font-bold animate-pulse">رمز الدخول غير صحيح!</p>}
            <button onClick={verifyLock} className="w-full bg-gradient-to-r from-[#FA8072] to-orange-600 text-white py-4 rounded-2xl font-black text-sm shadow-lg active:scale-95 transition-all">تأكيد الإجراء</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, Suspense, useCallback, useRef } from 'react';
import { Header } from './components/Header';
import { POSInterface } from './components/RecipeGenerator';
import { SalesTable } from './components/Menu';
import { Summary } from './components/InfoBox';
import { Login } from './components/Login';
import { SaleItem, Product, ArchivedDay, SaleType, Customer, PurchaseInvoice, Supplier } from './types';
import { Loader2, X, ShieldCheck, Wifi, WifiOff, CloudDownload, CheckCircle2, AlertCircle, Download, AlertTriangle, Heart } from 'lucide-react';

const InvoiceModal = React.lazy(() => import('./components/InvoiceModal').then(m => ({ default: m.InvoiceModal })));
const ProductManager = React.lazy(() => import('./components/ProductManager').then(m => ({ default: m.ProductManager })));
const HistoryModal = React.lazy(() => import('./components/HistoryModal').then(m => ({ default: m.HistoryModal })));
const DataManagementModal = React.lazy(() => import('./components/DataManagementModal').then(m => ({ default: m.DataManagementModal })));
const CustomerManager = React.lazy(() => import('./components/CustomerManager').then(m => ({ default: m.CustomerManager })));
const ExpensesModal = React.lazy(() => import('./components/ExpensesModal').then(m => ({ default: m.ExpensesModal })));
const AnalyticsModal = React.lazy(() => import('./components/AnalyticsModal').then(m => ({ default: m.AnalyticsModal })));

const ModalLoader = () => <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center"><div className="bg-gray-800 p-4 rounded-full border border-gray-700"><Loader2 className="animate-spin text-[#FA8072]" size={32} /></div></div>;

const WelcomeLoader: React.FC<{ onComplete: () => void }> = ({ onComplete }) => {
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    // التحميل يستغرق ثانيتين بالضبط (100ms * 20 step = 2000ms)
    const timer = setInterval(() => {
      setProgress((prev) => {
        if (prev >= 100) {
          clearInterval(timer);
          setTimeout(onComplete, 300); // تأخير بسيط جداً بعد اكتمال الـ 100% لنعومة الحركة
          return 100;
        }
        return prev + 5;
      });
    }, 100);

    return () => clearInterval(timer);
  }, [onComplete]);

  return (
    <div className="fixed inset-0 bg-gray-950 z-[300] flex flex-col items-center justify-center p-6 text-center overflow-hidden">
      {/* تأثيرات الخلفية */}
      <div className="absolute top-[-10%] left-[-10%] w-96 h-96 bg-[#FA8072]/20 rounded-full blur-[120px] animate-pulse"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-96 h-96 bg-blue-600/10 rounded-full blur-[150px] animate-pulse" style={{ animationDelay: '1s' }}></div>

      <div className="relative z-10 flex flex-col items-center">
        {/* أيقونة ترحيبية */}
        <div className="mb-8 relative scale-110">
           <div className="w-24 h-24 bg-gradient-to-tr from-[#FA8072] to-orange-600 rounded-[2.5rem] flex items-center justify-center mx-auto shadow-[0_0_50px_rgba(250,128,114,0.3)] animate-bounce">
              <ShieldCheck className="text-white" size={48} />
           </div>
           <div className="absolute -bottom-2 -right-2 bg-white text-[#FA8072] p-2 rounded-full shadow-xl animate-pulse">
              <Heart size={16} fill="currentColor" />
           </div>
        </div>

        {/* نص الترحيب الرئيسي */}
        <div className="space-y-2 mb-12">
            <h1 className="text-6xl font-black text-white tracking-tighter animate-fade-up" style={{ animationDuration: '0.8s' }}>
                مرحباً
            </h1>
            <p className="text-[#FA8072] text-xl font-bold opacity-80 animate-fade-up" style={{ animationDelay: '0.2s' }}>
                بك في مخبز كوكيز
            </p>
        </div>

        {/* شريط التحميل السفلي */}
        <div className="w-64 max-w-full">
            <div className="w-full bg-gray-900 h-1.5 rounded-full overflow-hidden border border-gray-800 p-0 mb-3">
              <div 
                className="h-full bg-gradient-to-r from-[#FA8072] to-orange-500 rounded-full transition-all duration-300 ease-out shadow-[0_0_15px_rgba(250,128,114,0.5)]" 
                style={{ width: `${progress}%` }}
              ></div>
            </div>
            <div className="flex justify-between items-center px-1">
                <span className="text-[10px] font-black text-gray-600 uppercase tracking-widest">System Booting</span>
                <span className="text-[#FA8072] font-black tabular-nums text-xs">{progress}%</span>
            </div>
        </div>
      </div>

      <div className="absolute bottom-10 text-gray-700 text-[10px] font-black uppercase tracking-[0.4em]">
          Cookie Bakery OS v2.6
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => sessionStorage.getItem('isAuth') === 'true');
  const [isInitializing, setIsInitializing] = useState(true); // تبدأ بـ true لتظهر شاشة الترحيب دائماً عند الفتح
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSyncTime, setLastSyncTime] = useState<Date>(() => new Date());
  const [showLock, setShowLock] = useState<{ target: string; data?: any } | null>(null);
  const [lockPass, setLockPass] = useState('');
  const [lockError, setLockError] = useState(false);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  // PWA Install Prompt State
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  useEffect(() => {
    const handleBeforeInstallPrompt = (e: any) => {
      e.preventDefault();
      setInstallPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    return () => window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
  }, []);

  const handleInstall = async () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    const { outcome } = await installPrompt.userChoice;
    if (outcome === 'accepted') {
      setInstallPrompt(null);
    }
  };

  const [systemPassword, setSystemPassword] = useState(() => localStorage.getItem('systemPassword') || '2026');

  const [showBackupReminder, setShowBackupReminder] = useState(false);
  const lastBackupTimestamp = useRef<number>(Date.now());

  const [sales, setSales] = useState<SaleItem[]>(() => JSON.parse(localStorage.getItem('dailySales') || '[]'));
  const [purchaseInvoices, setPurchaseInvoices] = useState<PurchaseInvoice[]>(() => JSON.parse(localStorage.getItem('dailyPurchaseInvoices') || '[]'));
  const [history, setHistory] = useState<ArchivedDay[]>(() => JSON.parse(localStorage.getItem('salesHistory') || '[]'));
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem('products') || '[]'));
  const [customers, setCustomers] = useState<Customer[]>(() => JSON.parse(localStorage.getItem('customers') || '[]'));
  const [suppliers, setSuppliers] = useState<Supplier[]>(() => JSON.parse(localStorage.getItem('suppliers') || '[]'));

  const [invoiceItems, setInvoiceItems] = useState<SaleItem[] | null>(null);
  const [modals, setModals] = useState({ products: false, customers: false, history: false, data: false, expenses: false, analytics: false });

  const handleLogout = () => {
    sessionStorage.removeItem('isAuth');
    setIsAuthenticated(false);
  };

  const handleOpenProtected = (target: string, data?: any) => {
    setShowLock({ target, data });
  };

  const completeOrder = useCallback((items: any[], customerName?: string, customerId?: string, saleType: SaleType = 'retail') => {
    const orderId = Date.now().toString();
    const time = new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: false });
    const todayDate = new Date().toLocaleDateString('en-US');

    const activeTodaySales = sales.filter(s => s.date === todayDate);
    const activeMax = activeTodaySales.length > 0 
      ? Math.max(...activeTodaySales.map(s => s.customerNumber)) 
      : 0;

    const archivedToday = history.find(h => h.date === todayDate);
    const archivedMax = (archivedToday && archivedToday.items.length > 0)
      ? Math.max(...archivedToday.items.map(s => s.customerNumber))
      : 0;

    const nextCustomerNumber = Math.max(activeMax, archivedMax) + 1;

    const newItems: SaleItem[] = items.map(item => ({
      ...item,
      id: Math.random().toString(36).substr(2, 9),
      orderId,
      customerNumber: nextCustomerNumber,
      customerName,
      customerId,
      saleType,
      time,
      date: todayDate
    }));

    setSales(prev => [...prev, ...newItems]);
    setInvoiceItems(newItems);
  }, [sales, history]);

  const handleUpdateProduct = (id: string, updatedProduct: Partial<Product>) => {
    setProducts(prev => prev.map(p => p.id === id ? { ...p, ...updatedProduct } : p));
  };

  const handleUpdateArchivedOrder = (dayId: string, orderId: string, updatedItems: SaleItem[], newCustomerName?: string) => {
    setHistory(prev => prev.map(day => {
      if (day.id === dayId) {
        const otherItems = day.items.filter(item => item.orderId !== orderId);
        const finalItems = [...otherItems, ...updatedItems.map(it => ({ ...it, customerName: newCustomerName || it.customerName }))];
        return {
          ...day,
          items: finalItems,
          totalRevenue: finalItems.reduce((s, i) => s + (i.price * i.quantity), 0),
          totalItems: finalItems.length
        };
      }
      return day;
    }));
  };

  const handleDeleteArchivedOrder = (dayId: string, orderId: string) => {
    setHistory(prev => {
      const updated = prev.map(day => {
        if (day.id === dayId) {
          const finalItems = day.items.filter(item => item.orderId !== orderId);
          return {
            ...day,
            items: finalItems,
            totalRevenue: finalItems.reduce((s, i) => s + (i.price * i.quantity), 0),
            totalItems: finalItems.length
          };
        }
        return day;
      });
      return updated.filter(day => day.items.length > 0 || (day.purchaseInvoices && day.purchaseInvoices.length > 0));
    });
  };

  const handleDeleteArchivedDay = (dayId: string) => {
    setHistory(prev => prev.filter(day => day.id !== dayId));
  };

  const handleLoginSuccess = () => {
    sessionStorage.setItem('isAuth', 'true');
    setIsAuthenticated(true);
  };

  const finalizeWelcome = () => {
    setIsInitializing(false);
  };

  useEffect(() => {
    if (!isAuthenticated) return;
    const CHECK_INTERVAL = 60 * 1000; 
    const REMINDER_INTERVAL = 60 * 60 * 1000; 
    const intervalId = setInterval(() => {
      const now = Date.now();
      if (now - lastBackupTimestamp.current >= REMINDER_INTERVAL) {
        setShowBackupReminder(true);
      }
    }, CHECK_INTERVAL);
    return () => clearInterval(intervalId);
  }, [isAuthenticated]);

  useEffect(() => {
    localStorage.setItem('dailySales', JSON.stringify(sales));
    localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(purchaseInvoices));
    localStorage.setItem('salesHistory', JSON.stringify(history));
    localStorage.setItem('products', JSON.stringify(products));
    localStorage.setItem('customers', JSON.stringify(customers));
    localStorage.setItem('suppliers', JSON.stringify(suppliers));
    localStorage.setItem('systemPassword', systemPassword);
    setLastSyncTime(new Date());
  }, [sales, purchaseInvoices, history, products, customers, suppliers, systemPassword]);

  const verifyLock = () => {
    if (lockPass === systemPassword) {
      if (showLock?.target === 'full_reset') {
          localStorage.clear();
          window.location.reload();
      } else if (showLock?.target === 'clear_all_history') {
          setHistory([]);
      } else if (showLock) {
          setModals(m => ({ ...m, [showLock.target]: true }));
      }
      setShowLock(null);
      setLockPass('');
      setLockError(false);
    } else {
      setLockError(true);
    }
  };

  const handleArchiveDay = useCallback(() => {
      if (sales.length === 0 && purchaseInvoices.length === 0) {
          alert('لا توجد عمليات مبيعات أو مشتريات نشطة حالياً لترحيلها.');
          return;
      }

      const confirmed = window.confirm('هل أنت متأكد من ترحيل المبيعات للأرشيف وتصفير اليوم؟ \n\nسيتم توزيع كل فاتورة حسب تاريخها الأصلي في السجلات التاريخية.');
      if (!confirmed) return;

      try {
          const currentSales = [...sales];
          const currentPurchases = [...purchaseInvoices];

          const salesMap = new Map<string, SaleItem[]>();
          currentSales.forEach(s => {
              const d = s.date;
              if (!salesMap.has(d)) salesMap.set(d, []);
              salesMap.get(d)!.push(s);
          });

          const purchaseMap = new Map<string, PurchaseInvoice[]>();
          currentPurchases.forEach(p => {
              const d = p.date;
              if (!purchaseMap.has(d)) purchaseMap.set(d, []);
              purchaseMap.get(d)!.push(p);
          });

          const allUniqueDates = Array.from(new Set([...salesMap.keys(), ...purchaseMap.keys()]));

          setHistory(prev => {
              const newHistory = [...prev];

              allUniqueDates.forEach(dateStr => {
                  const daySales = salesMap.get(dateStr) || [];
                  const dayPurchases = purchaseMap.get(dateStr) || [];

                  const rev = daySales.reduce((s, i) => s + (i.price * i.quantity), 0);
                  const exp = dayPurchases.reduce((s, i) => s + i.totalAmount, 0);

                  const existingIdx = newHistory.findIndex(h => h.date === dateStr);

                  if (existingIdx !== -1) {
                      newHistory[existingIdx] = {
                          ...newHistory[existingIdx],
                          items: [...newHistory[existingIdx].items, ...daySales],
                          purchaseInvoices: [...(newHistory[existingIdx].purchaseInvoices || []), ...dayPurchases],
                          totalRevenue: newHistory[existingIdx].totalRevenue + rev,
                          totalExpenses: newHistory[existingIdx].totalExpenses + exp,
                          totalItems: newHistory[existingIdx].totalItems + daySales.length
                      };
                  } else {
                      const refItem = daySales[0];
                      const ts = refItem ? parseInt(refItem.orderId) : Date.now();

                      newHistory.push({
                          id: `arch-${dateStr.replace(/[^0-9]/g, '')}-${Date.now()}`,
                          date: dateStr,
                          timestamp: ts,
                          items: daySales,
                          purchaseInvoices: dayPurchases,
                          totalRevenue: rev,
                          totalExpenses: exp,
                          totalItems: daySales.length
                      });
                  }
              });

              return newHistory.sort((a, b) => b.timestamp - a.timestamp);
          });

          setSales([]);
          setPurchaseInvoices([]);
          alert('تم ترحيل البيانات وتصفير اليوم بنجاح!');
      } catch (error) {
          console.error('Archive Error:', error);
          alert('حدث خطأ أثناء الترحيل.');
      }
  }, [sales, purchaseInvoices]);

  const handleExportData = async () => {
    const backup = { 
      dailySales: sales, 
      dailyPurchaseInvoices: purchaseInvoices, 
      salesHistory: history, 
      products, 
      customers, 
      suppliers, 
      systemPassword,
      exportDate: new Date().toISOString() 
    };
    const jsonString = JSON.stringify(backup);
    try {
      const stream = new Blob([jsonString]).stream();
      const compressedStream = stream.pipeThrough(new (window as any).CompressionStream('gzip'));
      const response = new Response(compressedStream);
      const compressedBlob = await response.blob();
      const url = URL.createObjectURL(compressedBlob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `cookies-bakery-pro-${new Date().toLocaleDateString('en-GB').replace(/\//g, '-')}.bak`;
      link.click();
      URL.revokeObjectURL(url);
      lastBackupTimestamp.current = Date.now();
      setShowBackupReminder(false);
    } catch (err) {
      const blob = new Blob([jsonString], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `cookies-bakery-legacy-${new Date().toLocaleDateString('en-GB').replace(/\//g, '-')}.json`;
      link.click();
      URL.revokeObjectURL(url);
    }
  };

  const handleImportData = async (file: File) => {
    try {
      let jsonString = '';
      if (file.name.endsWith('.bak')) {
        const stream = file.stream();
        const decompressedStream = stream.pipeThrough(new (window as any).DecompressionStream('gzip'));
        const response = new Response(decompressedStream);
        jsonString = await response.text();
      } else {
        jsonString = await file.text();
      }
      const data = JSON.parse(jsonString);
      if (data.dailySales) setSales(data.dailySales);
      if (data.dailyPurchaseInvoices) setPurchaseInvoices(data.dailyPurchaseInvoices);
      if (data.salesHistory) setHistory(data.salesHistory);
      if (data.products) setProducts(data.products);
      if (data.customers) setCustomers(data.customers);
      if (data.suppliers) setSuppliers(data.suppliers);
      if (data.systemPassword) setSystemPassword(data.systemPassword);
      alert('تمت استعادة البيانات بنجاح.');
    } catch (err) { 
      alert('خطأ في استعادة البيانات.'); 
    }
  };

  if (isInitializing) return <WelcomeLoader onComplete={finalizeWelcome} />;
  if (!isAuthenticated) return <Login onLogin={handleLoginSuccess} />;

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white relative">
      <Header 
        onOpenHistory={() => handleOpenProtected('history')} 
        onOpenDataManagement={() => handleOpenProtected('data')} 
        onOpenExpenses={() => handleOpenProtected('expenses')}
        onOpenAnalytics={() => handleOpenProtected('analytics')}
        onLogout={handleLogout}
        isOnline={isOnline} 
        lastSyncTime={lastSyncTime} 
        onManualSync={() => { setIsSyncing(true); setTimeout(() => setIsSyncing(false), 800); }} 
        onQuickBackup={handleExportData} 
        isSyncing={isSyncing}
        installPrompt={installPrompt}
        onInstall={handleInstall}
      />
      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl no-print">
        <Summary items={sales} onPreview={() => setInvoiceItems(sales)} systemPassword={systemPassword} />
        <POSInterface products={products} customers={customers} onCompleteOrder={completeOrder} onOpenProductManager={() => setModals(m => ({...m, products: true}))} onOpenCustomerManager={() => setModals(m => ({...m, customers: true}))} />
        <div className="mt-8">
            <SalesTable 
              items={sales} 
              onDeleteItem={(id: string) => setSales(s => s.filter(i => i.id !== id))} 
              onDeleteOrder={(oid: string) => setSales(s => s.filter(i => i.orderId !== oid))} 
              onPreviewInvoice={setInvoiceItems} 
              onUpdateItemPrice={(id: string, p: number) => setSales(s => s.map(i => i.id === id ? {...i, price: p} : i))} 
            />
        </div>
      </main>

      {showBackupReminder && (
        <div className="fixed bottom-6 right-6 left-6 md:left-auto md:w-80 bg-gray-800 border border-orange-500/50 p-5 rounded-[2rem] shadow-2xl z-[150] animate-fade-up flex flex-col gap-4 no-print">
            <div className="flex items-start gap-4">
                <div className="bg-orange-500/20 p-3 rounded-2xl text-orange-500 shrink-0"><AlertCircle size={24} /></div>
                <div className="flex-1">
                    <h4 className="text-white font-black text-sm">تذكير أمان البيانات</h4>
                    <p className="text-gray-400 text-[10px] font-bold mt-1 leading-relaxed">لقد مر وقت طويل منذ آخر نسخة احتياطية.</p>
                </div>
                <button onClick={() => setShowBackupReminder(false)} className="text-gray-500 hover:text-white"><X size={18} /></button>
            </div>
            <button onClick={handleExportData} className="w-full bg-orange-600 hover:bg-orange-500 text-white py-3 rounded-xl font-black text-xs flex items-center justify-center gap-2 transition-all"><Download size={14} /> نسخ مضغوط الآن</button>
        </div>
      )}

      <footer className="mt-12 py-8 border-t border-gray-800/50 text-center no-print">
         <button onClick={() => handleOpenProtected('full_reset')} className="text-gray-700 text-[10px] font-bold tracking-widest uppercase">نظام مبيعات كوكيز v2.6 • 2026</button>
      </footer>
      <Suspense fallback={<ModalLoader />}>
        {modals.analytics && <AnalyticsModal history={history} currentSales={sales} currentPurchases={purchaseInvoices} onClose={() => setModals(m => ({ ...m, analytics: false }))} />}
        {modals.expenses && <ExpensesModal isOpen={modals.expenses} onClose={() => setModals(m => ({...m, expenses: false}))} currentPurchases={purchaseInvoices} archivedHistory={history} onAddInvoice={v => setPurchaseInvoices(p => [...p, v])} onUpdateInvoice={v => setPurchaseInvoices(p => p.map(inv => inv.id === v.id ? v : inv))} onDeleteInvoice={id => setPurchaseInvoices(p => p.filter(v => v.id !== id))} suppliers={suppliers} onAddSupplier={s => setSuppliers(p => [...p, {...s, id: Date.now().toString()}])} onDeleteSupplier={id => setSuppliers(p => p.filter(s => s.id !== id))} />}
        {modals.history && <HistoryModal history={history} currentSales={sales} onClose={() => setModals(m => ({...m, history: false}))} onPreviewInvoice={setInvoiceItems} onUpdateOrder={handleUpdateArchivedOrder} onDeleteArchivedOrder={handleDeleteArchivedOrder} onDeleteArchivedDay={handleDeleteArchivedDay} />}
        {modals.products && <ProductManager isOpen={modals.products} onClose={() => setModals(m => ({...m, products: false}))} products={products} onAddProduct={p => setProducts(s => [...s, {...p, id: Date.now().toString()}])} onUpdateProduct={handleUpdateProduct} onDeleteProduct={id => setProducts(s => s.filter(p => p.id !== id))} />}
        {modals.customers && <CustomerManager isOpen={modals.customers} onClose={() => setModals(m => ({...m, customers: false}))} customers={customers} onAddCustomer={c => setCustomers(s => [...s, {...c, id: Date.now().toString()}])} onDeleteCustomer={id => setCustomers(s => s.filter(c => c.id !== id))} />}
        {modals.data && <DataManagementModal onClose={() => setModals(m => ({...m, data: false}))} onExport={handleExportData} onImport={handleImportData} onArchiveDay={handleArchiveDay} systemPassword={systemPassword} setSystemPassword={setSystemPassword} />}
        {invoiceItems && <InvoiceModal items={invoiceItems} onClose={() => setInvoiceItems(null)} />}
      </Suspense>
      {showLock && (
        <div className="fixed inset-0 bg-black/90 z-[200] flex items-center justify-center p-4 backdrop-blur-sm no-print">
          <div className="bg-gray-800 border border-gray-700 p-6 rounded-3xl w-full max-w-xs shadow-2xl animate-fade-up relative">
            <button onClick={() => { setShowLock(null); setLockPass(''); setLockError(false); }} className="absolute top-4 left-4 text-gray-500 hover:text-white transition-colors"><X size={20} /></button>
            <div className="text-center mb-6">
                <div className="w-12 h-12 bg-[#FA8072]/20 rounded-full flex items-center justify-center mx-auto mb-3"><Loader2 className="text-[#FA8072] animate-pulse" size={24} /></div>
                <h3 className="text-white font-black text-lg">تأكيد الإجراء</h3>
                <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest mt-1">أدخل كلمة المرور للمتابعة</p>
            </div>
            <input type="password" value={lockPass} onChange={e => setLockPass(e.target.value)} placeholder="رمز الدخول" className={`w-full bg-gray-900 border ${lockError ? 'border-red-500' : 'border-gray-700'} text-white p-4 rounded-2xl mb-4 text-center outline-none focus:border-[#FA8072] text-xl tracking-widest`} autoFocus onKeyDown={e => e.key === 'Enter' && verifyLock()} />
            {lockError && <p className="text-red-500 text-[10px] text-center mb-4 font-bold animate-pulse">رمز الدخول غير صحيح!</p>}
            <button onClick={verifyLock} className="w-full bg-gradient-to-r from-[#FA8072] to-orange-600 text-white py-4 rounded-2xl font-black text-sm shadow-lg active:scale-95 transition-all">تأكيد الإجراء</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;
